(function() {    'use strict';    // ============================================================    // حماية F12 وأدوات المطور    // ============================================================    document.addEventListener('keydown', function(e) {        if (e.key === 'F12' ||            (e.ctrlKey && e.shiftKey && (e.key === 'I' || e.key === 'i')) ||            (e.ctrlKey && e.shiftKey && (e.key === 'J' || e.key === 'j')) ||            (e.ctrlKey && (e.key === 'U' || e.key === 'u')) ||            (e.ctrlKey && (e.key === 'S' || e.key === 's')) ||            (e.ctrlKey && e.shiftKey && (e.key === 'C' || e.key === 'c'))) {            e.preventDefault();            showToast('warning', '⚠️ هذه الميزة غير متاحة');            return false;        }    });    document.addEventListener('contextmenu', function(e) {        e.preventDefault();        showToast('warning', '⚠️ هذه الميزة غير متاحة');        return false;    });    document.addEventListener('selectstart', function(e) {        if (e.target.tagName !== 'INPUT' && e.target.tagName !== 'TEXTAREA') {            e.preventDefault();        }    });    // ============================================================    // كشف أدوات المطورين - نسخة آمنة    // ============================================================    (function detectDevTools() {        var devtoolsOpen = false;        var threshold = 200;        var warningCount = 0;        var MAX_WARNINGS = 3;        function checkDevTools() {            var widthDiff = window.outerWidth - window.innerWidth;            var heightDiff = window.outerHeight - window.innerHeight;            if (widthDiff > threshold || heightDiff > threshold) {                if (!devtoolsOpen) {                    devtoolsOpen = true;                    warningCount++;                    console.warn('⚠️ تم اكتشاف أدوات المطورين (التنبيه ' + warningCount + '/' + MAX_WARNINGS + ')');                    if (warningCount >= MAX_WARNINGS) {                        showToast('warning', '⚠️ يرجى إغلاق أدوات المطورين لتحسين الأداء');                    }                }            } else {                devtoolsOpen = false;            }        }        setInterval(checkDevTools, 2000);        var resizeTimer;        window.addEventListener('resize', function() {            clearTimeout(resizeTimer);            resizeTimer = setTimeout(checkDevTools, 500);        });    })();    // ============================================================    // تعطيل console.log في الإنتاج    // ============================================================    if (window.location.hostname !== 'localhost' && window.location.hostname !== '127.0.0.1') {        console.log = function() {};        console.warn = function() {};        console.info = function() {};        console.error = function() {};    }    // ============================================================    // 🔑 قائمة المشرفين    // ============================================================    var ADMIN_EMAILS = [        'sajadsarmd200@gmail.com'    ];    // ============================================================    // تكوين Supabase    // ============================================================    var SUPABASE_URL = 'https://mgcljgrkxhyjjmxqjkti.supabase.co';    var SUPABASE_ANON_KEY = 'sb_publishable_TE4fMQARKZb0XcjhAnEJhA_ws6AUxoi';    var supabaseClient = null;    if (window.supabase) {        if (!window._supabaseClient) {            window._supabaseClient = supabase.createClient(SUPABASE_URL, SUPABASE_ANON_KEY);        }        supabaseClient = window._supabaseClient;    }    // ============================================================    // المتغيرات العامة    // ============================================================    var currentUser = null;    var data = { sections: [] };    var isDarkMode = false;    var isAdminLoggedIn = false;    var pendingChanges = 0;    var activeTeacher = null;    var activeTeacherIndex = null;    var activeSectionIndex = null;    var currentFilter = 'all';    var selectedClass = 'all';    var userDeviceId = getDeviceId();    var studentProgress = {};    // ============================================================    // الأقسام الافتراضية    // ============================================================    var defaultSections = [        { id: 'first-intermediate', name: 'أول متوسط', teachers: [] },        { id: 'second-intermediate', name: 'ثاني متوسط', teachers: [] },        { id: 'third-intermediate', name: 'ثالث متوسط', teachers: [] },        { id: 'fourth-scientific', name: 'رابع علمي', teachers: [] },        { id: 'fourth-literary', name: 'رابع أدبي', teachers: [] },        { id: 'fifth-scientific', name: 'خامس علمي', teachers: [] },        { id: 'fifth-literary', name: 'خامس أدبي', teachers: [] },        { id: 'sixth-scientific', name: 'سادس علمي', teachers: [] },        { id: 'sixth-literary', name: 'سادس أدبي', teachers: [] }    ];    // ============================================================    // عناصر DOM    // ============================================================    var loadingScreen = document.getElementById('loadingScreen');    var app = document.getElementById('app');    var navbar = document.getElementById('navbar');    var bottomNav = document.getElementById('bottomNav');    var teachersGridContainer = document.getElementById('teachersGridContainer');    var teachersGridContainer2 = document.getElementById('teachersGridContainer2');    var sectionFilter = document.getElementById('sectionFilter');    var sectionFilter2 = document.getElementById('sectionFilter2');    var teachersCount = document.getElementById('teachersCount');    var teachersCount2 = document.getElementById('teachersCount2');    var searchInput = document.getElementById('searchInput');    var searchBtn = document.getElementById('searchBtn');    var videoPlayer = document.getElementById('videoPlayer');    var closePlayer = document.getElementById('closePlayer');    var videoWrapper = document.getElementById('videoWrapper');    var themeToggle = document.getElementById('themeToggle');    var toastContainer = document.getElementById('toastContainer');    var userNameDisplay = document.getElementById('userNameDisplay');    var userAvatar = document.getElementById('userAvatar');    var classFilterSelect = document.getElementById('classFilterSelect');    // ============================================================    // عناصر ADMIN    // ============================================================    var adminPanel = document.getElementById('adminPanel');    var adminOverlay = document.getElementById('adminOverlay');    var adminClose = document.getElementById('adminClose');    var publishBtn = document.getElementById('publishBtn');    var pendingChangesSpan = document.getElementById('pendingChanges');    // ============================================================    // النماذج    // ============================================================    var addSectionForm = document.getElementById('addSectionForm');    var addTeacherForm = document.getElementById('addTeacherForm');    var addSemesterForm = document.getElementById('addSemesterForm');    var addLectureForm = document.getElementById('addLectureForm');    var editLectureForm = document.getElementById('editLectureForm');    // ============================================================    // النوافذ المنبثقة    // ============================================================    var teachersModal = document.getElementById('teachersModal');    var closeTeachersModal = document.getElementById('closeTeachersModal');    var teachersList = document.getElementById('teachersList');    var semestersModal = document.getElementById('semestersModal');    var closeSemestersModal = document.getElementById('closeSemestersModal');    var semestersList = document.getElementById('semestersList');    var modalTeacherTitle = document.getElementById('modalTeacherTitle');    var lecturesModal = document.getElementById('lecturesModal');    var closeLecturesModal = document.getElementById('closeLecturesModal');    var lecturesList = document.getElementById('lecturesList');    var modalSemesterTitle = document.getElementById('modalSemesterTitle');    var studentProgressModal = document.getElementById('studentProgressModal');    var closeStudentProgressModal = document.getElementById('closeStudentProgressModal');    var studentProgressTitle = document.getElementById('studentProgressTitle');    var studentProgressContent = document.getElementById('studentProgressContent');    // ============================================================    // صفحة الحساب    // ============================================================    var accountName = document.getElementById('accountName');    var accountEmail = document.getElementById('accountEmail');    var accountAvatar = document.getElementById('accountAvatar');    var accountRegistered = document.getElementById('accountRegistered');    var accountCourses = document.getElementById('accountCourses');    var accountCodes = document.getElementById('accountCodes');    var accountProgress = document.getElementById('accountProgress');    var accountLectures = document.getElementById('accountLectures');    var logoutAccountBtn = document.getElementById('logoutAccountBtn');    var adminPanelBtn = document.getElementById('adminPanelBtn');    var deleteAccountBtn = document.getElementById('deleteAccountBtn');    var coursesBadge = document.getElementById('coursesBadge');    var coursesBadgeMobile = document.getElementById('coursesBadgeMobile');    // ============================================================    // حذف الحساب    // ============================================================    var deleteAccountModal = document.getElementById('deleteAccountModal');    var closeDeleteModal = document.getElementById('closeDeleteModal');    var deletePasswordInput = document.getElementById('deletePasswordInput');    var deleteAccountMessage = document.getElementById('deleteAccountMessage');    // ============================================================    // DEVICE ID    // ============================================================    function getDeviceId() {        var deviceId = localStorage.getItem('deviceId');        if (!deviceId) {            deviceId = 'DEV_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);            localStorage.setItem('deviceId', deviceId);        }        return deviceId;    }    // ============================================================    // TOAST    // ============================================================    function showToast(type, message, duration) {        duration = duration || 4000;        var toast = document.createElement('div');        toast.className = 'toast ' + type;        var icons = { success: '✅', error: '❌', warning: '⚠️', info: 'ℹ️' };        toast.innerHTML = '<span>' + (icons[type] || '') + ' ' + message + '</span><button class="toast-close" onclick="this.parentElement.remove()">✕</button>';        toastContainer.appendChild(toast);        setTimeout(function() {            toast.style.animation = 'slideOut 0.4s ease forwards';            setTimeout(function() { toast.remove(); }, 400);        }, duration);    }    // ============================================================    // ✅ التحقق من المشرف    // ============================================================    async function checkIsAdmin(email) {        if (!email) return false;        if (ADMIN_EMAILS.includes(email)) {            console.log('✅ مشرف معروف محلياً:', email);            return true;        }        if (supabaseClient) {            try {                var result = await supabaseClient                    .from('admins')                    .select('email')                    .eq('email', email)                    .maybeSingle();                if (result.data) {                    console.log('✅ مشرف من Supabase:', email);                    return true;                }            } catch (e) {                console.warn('⚠️ فشل التحقق من Supabase:', e);            }        }        return false;    }    // ============================================================    // الوصول إلى المدرس    // ============================================================    function hasAccessToTeacher(teacher) {        if (!teacher || !teacher.codes) return false;        if (!currentUser) return false;        var hasAccess = teacher.codes.some(function(c) { return c.used && c.userEmail === currentUser.email && !c.locked; });        return hasAccess;    }    // ============================================================    // التحقق من الكود    // ============================================================    async function verifyCode(teacher, code) {        if (!teacher.codes || teacher.codes.length === 0) {            return { valid: false, message: 'لا توجد أكواد لهذا المدرس' };        }        if (!currentUser) {            return { valid: false, message: '⚠️ يجب تسجيل الدخول أولاً لإدخال الكود' };        }        var codeData = teacher.codes.find(function(c) { return c.code === code; });        if (!codeData) {            return { valid: false, message: '❌ الكود غير صحيح' };        }        if (codeData.locked === true) {            return { valid: false, message: '🔒 هذا الكود مقفل من قبل الإدارة' };        }        if (codeData.used) {            if (codeData.userEmail === currentUser.email) {                return { valid: true, message: '✅ الكود مفعل على حسابك' };            } else {                var usedAt = codeData.usedAt ? new Date(codeData.usedAt).toLocaleString('ar') : 'وقت غير معروف';                return {                    valid: false,                    message: '❌ هذا الكود مستخدم من قبل شخص آخر\n⏱️ تم الاستخدام في: ' + usedAt                };            }        }        codeData.used = true;        codeData.deviceId = userDeviceId;        codeData.userId = currentUser.id;        codeData.userEmail = currentUser.email;        codeData.usedAt = new Date().toISOString();        saveData();        var syncResult = await syncCodeWithSupabase(teacher, codeData);        if (!syncResult.success) {            codeData.used = false;            codeData.userId = null;            codeData.userEmail = null;            codeData.usedAt = null;            saveData();            return { valid: false, message: '❌ فشل حفظ الكود في قاعدة البيانات' };        }        await addCodeToUserCodes(currentUser.id, codeData.code);        updateUserCodesStorage();        renderAllData();        renderMyCourses();        renderAccount();        updateBadge();        return { valid: true, message: '✅ تم التفعيل بنجاح - تم حفظ الكود في حسابك' };    }    // ============================================================    // مزامنة الكود مع Supabase    // ============================================================    async function syncCodeWithSupabase(teacher, codeData) {        if (!currentUser || !supabaseClient) {            return { success: false, error: 'No authenticated user or Supabase unavailable' };        }        try {            var record = {                code: codeData.code,                teacher_name: teacher.name,                user_id: currentUser.id,                user_email: currentUser.email,                device_id: userDeviceId,                used: true,                locked: codeData.locked || false,                used_at: codeData.usedAt || new Date().toISOString(),            };            var result = await supabaseClient.from('teacher_codes').upsert(record, { onConflict: 'code' });            if (result.error) {                console.warn('⚠️ فشل مزامنة الكود مع Supabase:', result.error.message || result.error);                return { success: false, error: result.error };            }            var updateResult = await supabaseClient.from('codes').update({                is_used: true,                user_id: currentUser.id,                user_email: currentUser.email,                device_id: userDeviceId,                used_at: new Date().toISOString()            }).eq('code', codeData.code);            if (updateResult.error) {                console.warn('⚠️ فشل تحديث الكود في جدول codes:', updateResult.error);            }            console.log('✅ تم مزامنة الكود مع Supabase:', codeData.code);            return { success: true };        } catch (error) {            console.warn('⚠️ خطأ في مزامنة الكود:', error);            return { success: false, error: error };        }    }    // ============================================================    // إضافة كود إلى المستخدم    // ============================================================    async function addCodeToUserCodes(userId, code) {        if (!supabaseClient) return;        try {            var codeResult = await supabaseClient                .from('codes').select('id').eq('code', code).single();            if (codeResult.error) {                console.warn('⚠️ الكود غير موجود في قاعدة البيانات:', codeResult.error);                return;            }            var existingResult = await supabaseClient                .from('user_codes').select('id').eq('user_id', userId).eq('code_id', codeResult.data.id).maybeSingle();            if (existingResult.data) {                console.log('✅ الكود موجود مسبقاً للمستخدم');                return;            }            var insertResult = await supabaseClient.from('user_codes').insert({                user_id: userId,                code_id: codeResult.data.id,                used_at: new Date().toISOString()            });            if (insertResult.error) {                console.warn('⚠️ فشل حفظ الكود في user_codes:', insertResult.error);            } else {                console.log('✅ تم حفظ الكود في حساب المستخدم:', code);            }        } catch (error) {            console.warn('⚠️ خطأ في حفظ الكود:', error);        }    }    // ============================================================    // تحديث أكواد المستخدم في التخزين المحلي    // ============================================================    function updateUserCodesStorage() {        if (!currentUser) return;        var userCodes = [];        data.sections.forEach(function(section) {            section.teachers.forEach(function(teacher) {                if (teacher.codes) {                    teacher.codes.forEach(function(code) {                        if (code.used && code.userEmail === currentUser.email) {                            userCodes.push({                                code: code.code,                                teacherName: teacher.name,                                sectionName: section.name,                                usedAt: code.usedAt                            });                        }                    });                }            });        });        localStorage.setItem('userCodes_' + currentUser.email, JSON.stringify(userCodes));    }    // ============================================================    // استعادة أكواد المستخدم من التخزين المحلي    // ============================================================    function restoreUserCodesFromStorage() {        if (!currentUser) return;        var stored = localStorage.getItem('userCodes_' + currentUser.email);        if (!stored) return;        try {            var userCodes = JSON.parse(stored);            userCodes.forEach(function(savedCode) {                data.sections.forEach(function(section) {                    section.teachers.forEach(function(teacher) {                        if (teacher.codes) {                            var codeData = teacher.codes.find(function(c) { return c.code === savedCode.code; });                            if (codeData && !codeData.used) {                                codeData.used = true;                                codeData.userId = currentUser.id;                                codeData.userEmail = currentUser.email;                                codeData.deviceId = userDeviceId;                                codeData.usedAt = savedCode.usedAt || new Date().toISOString();                            }                        }                    });                });            });            saveData();        } catch (e) {            console.warn('⚠️ فشل استعادة الأكواد من التخزين المحلي');        }    }    // ============================================================    // تحميل أكواد المستخدم من Supabase    // ============================================================    async function loadUserCodesFromSupabase() {        if (!currentUser || !supabaseClient) return;        restoreUserCodesFromStorage();        try {            var codesResult = await supabaseClient                .from('user_codes').select('code_id').eq('user_id', currentUser.id);            if (codesResult.error) {                console.warn('⚠️ فشل جلب الأكواد:', codesResult.error);                return;            }            if (!codesResult.data || codesResult.data.length === 0) return;            var codeIds = codesResult.data.map(function(uc) { return uc.code_id; });            var detailsResult = await supabaseClient                .from('codes').select('*').in('id', codeIds);            if (detailsResult.error) {                console.warn('⚠️ فشل جلب تفاصيل الأكواد:', detailsResult.error);                return;            }            var restoredCount = 0;            detailsResult.data.forEach(function(codeRecord) {                data.sections.forEach(function(section) {                    section.teachers.forEach(function(teacher) {                        if (!teacher.codes) teacher.codes = [];                        var localCode = teacher.codes.find(function(c) { return c.code === codeRecord.code; });                        if (localCode) {                            if (!localCode.used) {                                localCode.used = true;                                localCode.userId = currentUser.id;                                localCode.userEmail = currentUser.email;                                localCode.deviceId = codeRecord.device_id || userDeviceId;                                localCode.usedAt = codeRecord.used_at || new Date().toISOString();                                localCode.locked = codeRecord.is_locked || false;                                restoredCount++;                            }                        }                    });                });            });            if (restoredCount > 0) {                saveData();                updateUserCodesStorage();                renderAllData();                renderMyCourses();                renderAccount();                updateBadge();                console.log('✅ تم استعادة', restoredCount, 'كود من Supabase');                showToast('success', '✅ تم استعادة ' + restoredCount + ' اشتراك محفوظ');            }        } catch (error) {            console.warn('⚠️ خطأ في تحميل الأكواد:', error);        }    }    // ============================================================    // حالة الأكواد    // ============================================================    function getCodesStatus(teacher) {        if (!teacher.codes) return { total: 0, used: 0, available: 0, locked: 0 };        var total = teacher.codes.length;        var used = teacher.codes.filter(function(c) { return c.used; }).length;        var locked = teacher.codes.filter(function(c) { return c.locked; }).length;        return { total: total, used: used, available: total - used, locked: locked };    }    // ============================================================    // دوال البيانات    // ============================================================    function normalizeDataStructure(courseData) {        if (!courseData || !Array.isArray(courseData.sections)) {            courseData.sections = [];        }        courseData.sections.forEach(function(section) {            if (!Array.isArray(section.teachers)) { section.teachers = []; }            section.teachers.forEach(function(teacher) {                if (!Array.isArray(teacher.codes)) { teacher.codes = []; }                if (!Array.isArray(teacher.semesters)) { teacher.semesters = []; }                teacher.codes.forEach(function(c) {                    if (c.used === undefined) c.used = false;                    if (c.locked === undefined) c.locked = false;                    if (!('deviceId' in c)) c.deviceId = null;                    if (!('usedAt' in c)) c.usedAt = null;                    if (!('userId' in c)) c.userId = null;                    if (!('userEmail' in c)) c.userEmail = null;                });                teacher.semesters.forEach(function(semester) {                    if (!Array.isArray(semester.lectures)) { semester.lectures = []; }                    semester.lectures.forEach(function(lecture) {                        if (lecture.isFree === undefined) lecture.isFree = false;                        if (!('youtubeUrl' in lecture)) lecture.youtubeUrl = '';                        if (!('title' in lecture)) lecture.title = '';                        if (lecture.number === undefined) lecture.number = 0;                    });                });            });        });    }    async function loadData() {        try {            if (supabaseClient) {                var remoteData = await getSupabaseAcademyData();                if (remoteData && remoteData.sections && Array.isArray(remoteData.sections)) {                    data = remoteData;                    normalizeDataStructure(data);                    localStorage.setItem('academyData', JSON.stringify(data));                    console.log('✅ تم تحميل البيانات من Supabase');                    return;                }            }            var savedData = localStorage.getItem('academyData');            if (savedData) {                try {                    var parsed = JSON.parse(savedData);                    if (parsed && parsed.sections && Array.isArray(parsed.sections)) {                        data = parsed;                        normalizeDataStructure(data);                        console.log('✅ تم تحميل البيانات من localStorage');                        return;                    }                } catch (e) { console.warn('⚠️ بيانات localStorage تالفة'); }            }            data = { sections: JSON.parse(JSON.stringify(defaultSections)) };            normalizeDataStructure(data);            localStorage.setItem('academyData', JSON.stringify(data));            showToast('info', '📝 تم تحميل الأقسام الافتراضية');        } catch (error) {            console.warn('⚠️ استخدام البيانات الافتراضية:', error.message);        }    }    function saveData() {        try {            localStorage.setItem('academyData', JSON.stringify(data));            console.log('✅ تم حفظ البيانات بنجاح');        } catch (error) {            console.error('❌ خطأ في حفظ البيانات:', error);            showToast('error', '⚠️ فشل حفظ البيانات محلياً');        }    }    async function getSupabaseAcademyData() {        if (!supabaseClient) return null;        try {            var result = await supabaseClient                .from('academy_data').select('content').eq('id', 'main').maybeSingle();            if (result.error) { console.warn('Supabase academy data lookup failed:', result.error.message || result.error); return null; }            return result.data?.content || null;        } catch (error) { console.warn('Supabase academy data exception:', error); return null; }    }    async function saveSupabaseAcademyData() {        if (!supabaseClient) return { success: false, error: 'Supabase غير متاح' };        try {            var record = { id: 'main', content: data, updated_at: new Date().toISOString() };            var result = await supabaseClient.from('academy_data').upsert(record, { onConflict: 'id' });            if (result.error) { console.warn('Supabase academy data save failed:', result.error.message || result.error); return { success: false,                    error: result.error }; }            localStorage.setItem('academyData', JSON.stringify(data));            return { success: true };        } catch (error) { console.warn('Supabase academy data save exception:', error); return { success: false,                error: error }; }    }    // ============================================================    // عرض البيانات مع الفلتر    // ============================================================    function getAllTeachers() {        var teachers = [];        data.sections.forEach(function(section, sectionIndex) {            section.teachers.forEach(function(teacher, teacherIndex) {                teachers.push({                    ...teacher,                    _sectionIndex: sectionIndex,                    _teacherIndex: teacherIndex,                    _sectionName: section.name,                    _sectionId: section.id                });            });        });        return teachers;    }    function getTeachersBySection(sectionId) {        var section = data.sections.find(function(s) { return s.id === sectionId; });        if (!section) return [];        return section.teachers.map(function(teacher, index) {            return {                ...teacher,                _sectionIndex: data.sections.indexOf(section),                _teacherIndex: index,                _sectionName: section.name,                _sectionId: section.id            };        });    }    function getFilteredTeachers() {        if (currentFilter === 'all') {            return getAllTeachers();        }        return getTeachersBySection(currentFilter);    }    // ============================================================    // فلتر الصفوف من القائمة المنسدلة    // ============================================================    window.filterByClass = function() {        var value = classFilterSelect.value;        selectedClass = value;        currentFilter = value;        renderAllData();    };    // ============================================================    // تحديث قائمة الصفوف    // ============================================================    function updateClassFilter() {        if (!classFilterSelect) return;        var currentValue = classFilterSelect.value;        var options = '<option value="all" class="all-classes">🎯 جميع الصفوف</option>';        data.sections.forEach(function(section) {            var teacherCount = section.teachers ? section.teachers.length : 0;            options += '<option value="' + section.id + '">📚 ' + section.name + ' (' + teacherCount + ')</option>';        });        classFilterSelect.innerHTML = options;        if (currentValue && data.sections.find(function(s) { return s.id === currentValue; })) {            classFilterSelect.value = currentValue;        }    }    // ============================================================    // بناء أزرار الفلتر - تم إخفاؤها بالكامل    // ============================================================    function buildFilterButtons(container, countContainer) {        // لا شيء - تم إلغاء أزرار الفلتر        if (container) container.innerHTML = '';        if (countContainer) countContainer.textContent = getAllTeachers().length;    }    // ============================================================    // عرض المدرسين    // ============================================================    function renderTeachers(teachers, container) {        if (!container) return;        if (!teachers || teachers.length === 0) {            container.innerHTML =                '<div class="empty-teachers">' +                '<span class="empty-icon">👨‍🏫</span>' +                '<h3>لا يوجد مدرسون</h3>' +                '<p>' + (currentFilter === 'all' ? 'قم بإضافة مدرسين من لوحة التحكم' : 'لا يوجد مدرسون في هذا القسم') + '</p>' +                '</div>';            return;        }        var html = '<div class="teachers-grid">';        teachers.forEach(function(teacher) {            var hasAccess = hasAccessToTeacher(teacher);            var imageUrl = teacher.image || '';            var emoji = teacher.emoji || '👨‍🏫';            var name = teacher.name || 'مدرس';            var subject = teacher.subject || '';            var semestersCount = Array.isArray(teacher.semesters) ? teacher.semesters.length : 0;            var sectionName = teacher._sectionName || '';            html +=                '<div class="teacher-card" onclick="openTeacher(' + teacher._sectionIndex + ', ' + teacher._teacherIndex + ')">' +                '<div class="teacher-section-badge">' + sectionName + '</div>' +                '<div class="teacher-card-image">' +                (imageUrl ? '<img src="' + imageUrl + '" alt="' + name + '" onerror="this.style.display=\'none\'; this.parentElement.querySelector(\'.teacher-emoji\').style.display=\'block\';">' : '') +                '<span class="teacher-emoji" style="' + (imageUrl ? 'display:none;' : 'display:block;') + '">' + emoji + '</span>' +                '</div>' +                '<div class="teacher-card-info">' +                '<h3>' + name + '</h3>' +                (subject ? '<div class="teacher-subject">' + subject + '</div>' : '') +                '<div class="teacher-stats">📚 ' + semestersCount + ' فصول</div>' +                '</div>' +                '<div class="teacher-card-overlay">' +                '<i class="fas fa-chevron-left"></i>' +                '<span>عرض</span>' +                '</div>' +                '</div>';        });        html += '</div>';        container.innerHTML = html;    }    function renderAllData() {        var filteredTeachers = getFilteredTeachers();        if (teachersCount) teachersCount.textContent = filteredTeachers.length;        if (teachersCount2) teachersCount2.textContent = filteredTeachers.length;        renderTeachers(filteredTeachers, teachersGridContainer);        renderTeachers(filteredTeachers, teachersGridContainer2);        buildFilterButtons(sectionFilter, teachersCount);        buildFilterButtons(sectionFilter2, teachersCount2);        updateClassFilter();        // تحديث إحصائيات الهيرو        var totalTeachers = getAllTeachers().length;        var totalTeachersEl = document.getElementById('totalTeachers');        if (totalTeachersEl) totalTeachersEl.textContent = totalTeachers;        var totalCourses = 0;        var uniqueStudents = new Set();        data.sections.forEach(function(section) {            section.teachers.forEach(function(teacher) {                totalCourses += teacher.semesters ? teacher.semesters.length : 0;                if (teacher.codes) {                    teacher.codes.forEach(function(c) {                        if (c.used && c.userEmail) {                            uniqueStudents.add(c.userEmail);                        }                    });                }            });        });        var totalCoursesEl = document.getElementById('totalCourses');        if (totalCoursesEl) totalCoursesEl.textContent = totalCourses;        var totalStudentsEl = document.getElementById('totalStudents');        if (totalStudentsEl) totalStudentsEl.textContent = uniqueStudents.size;        // تحديث إحصائيات لوحة التحكم        var adminTotalTeachers = document.getElementById('adminTotalTeachers');        if (adminTotalTeachers) adminTotalTeachers.textContent = totalTeachers;        var adminTotalSections = document.getElementById('adminTotalSections');        if (adminTotalSections) adminTotalSections.textContent = data.sections.length;        var totalLectures = 0;        data.sections.forEach(function(section) {            section.teachers.forEach(function(teacher) {                if (teacher.semesters) {                    teacher.semesters.forEach(function(semester) {                        totalLectures += semester.lectures ? semester.lectures.length : 0;                    });                }            });        });        var adminTotalLectures = document.getElementById('adminTotalLectures');        if (adminTotalLectures) adminTotalLectures.textContent = totalLectures;        var adminTotalStudents = document.getElementById('adminTotalStudents');        if (adminTotalStudents) adminTotalStudents.textContent = uniqueStudents.size;        // تحديث صورة الإعلان        var savedBanner = localStorage.getItem('bannerImage');        var mainBanner = document.getElementById('mainBannerImage');        var mainPlaceholder = document.getElementById('mainBannerPlaceholder');        if (savedBanner && mainBanner) {            mainBanner.src = savedBanner;            mainBanner.style.display = 'block';            if (mainPlaceholder) mainPlaceholder.style.display = 'none';        }    }    // ============================================================    // تتبع تقدم الطالب    // ============================================================    function loadStudentProgress() {        var saved = localStorage.getItem('studentProgress_' + (currentUser ? currentUser.id : 'guest'));        if (saved) {            try {                studentProgress = JSON.parse(saved);            } catch (e) {                studentProgress = {};            }        }    }    function saveStudentProgress() {        if (currentUser) {            localStorage.setItem('studentProgress_' + currentUser.id, JSON.stringify(studentProgress));        }    }    function markLectureWatched(teacherId, semesterIndex, lectureIndex) {        var key = teacherId + '_' + semesterIndex + '_' + lectureIndex;        if (!studentProgress[key]) {            studentProgress[key] = {                watched: true,                watchedAt: new Date().toISOString()            };            saveStudentProgress();        }    }    function isLectureWatched(teacherId, semesterIndex, lectureIndex) {        var key = teacherId + '_' + semesterIndex + '_' + lectureIndex;        return studentProgress[key] && studentProgress[key].watched === true;    }    function getStudentProgressForTeacher(teacherId) {        var progress = [];        var teacher = null;        var sectionIndex = -1;        var teacherIndex = -1;        data.sections.forEach(function(section, si) {            section.teachers.forEach(function(t, ti) {                if (t.id === teacherId || t.name === teacherId) {                    teacher = t;                    sectionIndex = si;                    teacherIndex = ti;                }            });        });        if (!teacher) return progress;        teacher.semesters.forEach(function(semester, si) {            semester.lectures.forEach(function(lecture, li) {                var key = teacherId + '_' + si + '_' + li;                var watched = studentProgress[key] && studentProgress[key].watched === true;                progress.push({                    semester: si + 1,                    lectureNumber: lecture.number,                    lectureTitle: lecture.title,                    watched: watched,                    watchedAt: watched ? studentProgress[key].watchedAt : null                });            });        });        return progress;    }    function getStudentOverallProgress(teacherId) {        var progress = getStudentProgressForTeacher(teacherId);        var total = progress.length;        var watched = progress.filter(function(p) { return p.watched; }).length;        return total > 0 ? Math.round((watched / total) * 100) : 0;    }    // ============================================================    // عرض تقدم الطالب    // ============================================================    window.showStudentProgress = function(studentEmail, teacherName) {        studentProgressTitle.textContent = '📊 تقدم الطالب: ' + studentEmail;        var progress = getStudentProgressForTeacher(teacherName);        var overall = getStudentOverallProgress(teacherName);        var html = '<div style="margin-bottom:0.5rem;">';        html += '<div style="background:var(--bg);border-radius:var(--radius-sm);padding:0.5rem;margin-bottom:0.3rem;">';        html += '<div style="display:flex;justify-content:space-between;font-size:0.7rem;font-weight:700;">';        html += '<span>التقدم العام: ' + overall + '%</span>';        html += '<span>' + progress.filter(function(p) { return p.watched; }).length + '/' + progress.length + ' محاضرة</span>';        html += '</div>';        html += '<div style="width:100%;height:6px;background:var(--bg);border-radius:10px;overflow:hidden;margin-top:0.1rem;">';        html += '<div style="height:100%;border-radius:10px;background:var(--primary-gradient);width:' + overall + '%;transition:width 0.6s ease;"></div>';        html += '</div></div>';        if (progress.length === 0) {            html += '<p style="text-align:center;color:var(--text-light);font-size:0.7rem;padding:0.5rem 0;">لا توجد محاضرات مسجلة لهذا المدرس</p>';        } else {            html += '<div class="progress-detail">';            progress.forEach(function(p) {                var statusClass = p.watched ? 'status-done' : 'status-pending';                var statusText = p.watched ? '✅ تم المشاهدة' : '⏳ لم تشاهد';                html += '<div class="progress-item">';                html += '<span>📖 الفصل ' + p.semester + ' - #' + p.lectureNumber + ' ' + p.lectureTitle + '</span>';                html += '<span class="' + statusClass + '">' + statusText + '</span>';                html += '</div>';            });            html += '</div>';        }        html += '</div>';        studentProgressContent.innerHTML = html;        studentProgressModal.classList.add('active');        document.body.style.overflow = 'hidden';    };    if (closeStudentProgressModal) {        closeStudentProgressModal.addEventListener('click', function() {            studentProgressModal.classList.remove('active');            document.body.style.overflow = 'auto';        });    }    if (studentProgressModal) {        studentProgressModal.addEventListener('click', function(e) {            if (e.target === this) {                studentProgressModal.classList.remove('active');                document.body.style.overflow = 'auto';            }        });    }    // ============================================================    // تشغيل الفيديو    // ============================================================    function extractVideoUrl(url) {        if (!url) return '';        if (url.includes('dyntube.com') || url.includes('videos.dyntube.com')) {            var embedUrl = url;            if (url.includes('/iframes/')) {                var videoId = url.split('/iframes/')[1]?.split('?')[0] || '';                if (videoId) embedUrl = 'https://dyntube.com/embed/' + videoId;            } else if (url.includes('/video/')) {                var videoId = url.split('/video/')[1]?.split('?')[0] || '';                if (videoId) embedUrl = 'https://dyntube.com/embed/' + videoId;            } else if (url.includes('/watch/')) {                var videoId = url.split('/watch/')[1]?.split('?')[0] || '';                if (videoId) embedUrl = 'https://dyntube.com/embed/' + videoId;            } else if (!url.includes('/embed/')) {                var videoId = url.split('/').pop()?.split('?')[0] || '';                if (videoId && videoId.length > 5) embedUrl = 'https://dyntube.com/embed/' + videoId;            }            var separator = embedUrl.includes('?') ? '&' : '?';            embedUrl = embedUrl + separator + 'autoplay=1&controls=1&loop=0&muted=0';            return embedUrl;        }        if (url.includes('player.mediadelivery.net/play/') || url.includes('player.mediadelivery.net/embed/') || url            .includes('mediadelivery.net')) {            return url;        }        if (url.includes('<iframe')) {            var match = url.match(/src=["']([^"']+)["']/);            if (match) return match[1];        }        return url;    }    function isDynTubeUrl(url) {        if (!url) return false;        return url.includes('dyntube.com') || url.includes('videos.dyntube.com') || url.includes('dyntube');    }    window.playVideo = function(url, title, teacherId, semesterIndex, lectureIndex) {        if (!url) {            showToast('error', '❌ رابط الفيديو غير موجود');            return;        }        // تسجيل تقدم الطالب        if (currentUser && teacherId) {            markLectureWatched(teacherId, semesterIndex, lectureIndex);            renderAllData();            renderMyCourses();            renderAccount();        }        var videoUrl = extractVideoUrl(url);        if (isDynTubeUrl(videoUrl)) {            if (!videoUrl.includes('/embed/')) {                var videoId = videoUrl.split('/').pop()?.split('?')[0] || '';                if (videoId && videoId.length > 5) {                    videoUrl = 'https://dyntube.com/embed/' + videoId;                }            }            var separator = videoUrl.includes('?') ? '&' : '?';            videoUrl = videoUrl + separator + 'autoplay=1&controls=1&loop=0&muted=0';            videoWrapper.innerHTML =                '<iframe src="' + videoUrl + '" loading="lazy" style="border:0;position:absolute;top:0;left:0;height:100%;width:100%;" allow="accelerometer;gyroscope;autoplay;encrypted-media;picture-in-picture;fullscreen;" allowfullscreen="true" webkitallowfullscreen="true" mozallowfullscreen="true"></iframe>';            videoPlayer.classList.add('active');            document.body.style.overflow = 'hidden';            showToast('info', '🎬 تشغيل: ' + (title || 'محاضرة') + ' (DynTube)');            return;        }        if (videoUrl.includes('mediadelivery')) {            if (!videoUrl.includes('autoplay')) {                var separator = videoUrl.includes('?') ? '&' : '?';                videoUrl = videoUrl + separator + 'autoplay=true&loop=false&muted=false&preload=true&responsive=true&controls=true';            }            videoUrl = videoUrl.replace(/&?muted=true/g, '');            videoUrl = videoUrl.replace(/&?muted=false/g, '');            videoWrapper.innerHTML =                '<iframe src="' + videoUrl + '" loading="lazy" style="border:0;position:absolute;top:0;left:0;height:100%;width:100%;" allow="accelerometer;gyroscope;autoplay;encrypted-media;picture-in-picture;fullscreen;" allowfullscreen="true" webkitallowfullscreen="true" mozallowfullscreen="true"></iframe>';            videoPlayer.classList.add('active');            document.body.style.overflow = 'hidden';            showToast('info', '🎬 تشغيل: ' + (title || 'محاضرة'));            return;        }        var videoId = extractYouTubeId(videoUrl);        if (videoId) {            var embedUrl = getYouTubeEmbedUrl(videoId);            videoWrapper.innerHTML =                '<iframe src="' + embedUrl + '" style="border:0;position:absolute;top:0;left:0;height:100%;width:100%;" allow="accelerometer;autoplay;clipboard-write;encrypted-media;gyroscope;picture-in-picture;fullscreen" allowfullscreen></iframe>';            videoPlayer.classList.add('active');            document.body.style.overflow = 'hidden';            showToast('info', '🎬 تشغيل: ' + (title || 'محاضرة'));            return;        }        if (videoUrl.match(/\.(mp4|webm|ogg|m3u8)(\?.*)?$/i)) {            videoWrapper.innerHTML =                '<video controls autoplay style="position:absolute;top:0;left:0;height:100%;width:100%;background:#000;" controlslist="nodownload" playsinline><source src="' + videoUrl + '" type="video/mp4">متصفحك لا يدعم تشغيل الفيديو</video>';            setTimeout(function() {                var video = videoWrapper.querySelector('video');                if (video) {                    video.volume = 1.0;                    video.muted = false;                }            }, 500);            videoPlayer.classList.add('active');            document.body.style.overflow = 'hidden';            showToast('info', '🎬 تشغيل: ' + (title || 'محاضرة'));            return;        }        showToast('error', '❌ رابط الفيديو غير صحيح. استخدم رابط mediadelivery أو YouTube أو DynTube');    };    function closeVideoPlayer() {        if (videoWrapper) videoWrapper.innerHTML = '';        if (videoPlayer) videoPlayer.classList.remove('active');        document.body.style.overflow = 'auto';    }    function extractYouTubeId(url) {        if (!url) return null;        var patterns = [            /(?:youtube\.com\/watch\?v=)([^&]+)/,            /(?:youtu\.be\/)([^?]+)/,            /(?:youtube\.com\/embed\/)([^?]+)/        ];        for (var i = 0; i < patterns.length; i++) {            var match = url.match(patterns[i]);            if (match) return match[1];        }        return null;    }    function getYouTubeEmbedUrl(videoId) {        return 'https://www.youtube.com/embed/' + videoId + '?autoplay=1&rel=0&modestbranding=1';    }    // ============================================================    // فتح المدرس    // ============================================================    window.openTeacher = function(sectionIndex, teacherIndex) {        var section = data.sections[sectionIndex];        if (!section) return;        var teacher = section.teachers[teacherIndex];        if (!teacher) return;        if (!teacher.id) {            teacher.id = 'teacher_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);        }        activeTeacher = teacher;        activeTeacherIndex = teacherIndex;        activeSectionIndex = sectionIndex;        var hasAccess = hasAccessToTeacher(teacher);        modalTeacherTitle.textContent = '👨‍🏫 ' + teacher.name + ' (' + section.name + ')';        var semesters = Array.isArray(teacher.semesters) ? teacher.semesters : [];        var html = '';        semesters.forEach(function(semester, idx) {            var lectures = Array.isArray(semester.lectures) ? semester.lectures : [];            var hasFreeLecture = lectures.some(function(l) { return l.isFree === true; });            var isLocked = !hasAccess && !hasFreeLecture;            var completedCount = 0;            lectures.forEach(function(lecture, li) {                if (isLectureWatched(teacher.id, idx, li)) {                    completedCount++;                }            });            var progressPercent = lectures.length > 0 ? Math.round((completedCount / lectures.length) * 100) : 0;            html +=                '<div class="semester-item ' + (isLocked ? 'locked' : '') + '" onclick="' + (isLocked ? '' : 'openLectures(' + sectionIndex + ', ' + teacherIndex + ', ' + idx + ')') + '">' +                '<div style="flex:1;">' +                '<div class="semester-number">📖 الفصل ' + semester.number + '</div>' +                '<div class="semester-desc">' + (semester.description || '') + ' (' + semester.lectures.length + ' محاضرة)</div>' +                (hasAccess || hasFreeLecture ? '<div style="font-size:0.55rem;color:var(--text-light);margin-top:0.05rem;">✅ ' + completedCount + '/' + semester.lectures.length + ' مكتمل (' + progressPercent + '%)</div>' : '') +                '</div>' +                '<div class="semester-status">' +                (isLocked ? '🔒 مغلق' : (hasAccess ? '✅ مفتوح' : '🆓 جزئياً')) +                '<i class="fas fa-chevron-left"></i>' +                '</div>' +                '</div>';        });        var isActivated = hasAccessToTeacher(teacher);        html +=            '<div class="codes-info">' +            '<div class="access-status ' + (isActivated ? 'active' : 'inactive') + '">' +            (isActivated ? '✅ تم التفعيل - جميع المحاضرات مفتوحة' : '🔒 بعض المحاضرات مقفلة - أدخل كود التفعيل') +            '</div>' +            (!isActivated ?                '<div class="code-box-mini" style="margin-top:0.5rem;background:var(--bg);padding:0.5rem;border-radius:var(--radius-sm);">' +                '<p style="font-size:0.65rem;margin-bottom:0.15rem;">🔑 أدخل كود التفعيل لفتح جميع المحاضرات</p>' +                '<div style="display:flex;gap:0.3rem;flex-wrap:wrap;">' +                '<input type="password" id="codeInputTeacher" placeholder="أدخل الكود..." maxlength="20" style="flex:1;min-width:80px;padding:0.3rem 0.5rem;border:2px solid var(--border);border-radius:6px;background:var(--bg-card);color:var(--text);font-size:0.75rem;outline:none;text-align:center;letter-spacing:2px;font-weight:700;font-family:monospace;" />' +                '<button onclick="activateCodeFromTeacher()" style="padding:0.3rem 0.8rem;background:var(--primary-gradient);color:white;border:none;border-radius:6px;font-weight:600;cursor:pointer;font-size:0.7rem;">تفعيل</button>' +                '</div>' +                '<div id="codeMessageTeacher" style="margin-top:0.2rem;font-size:0.7rem;"></div>' +                '</div>' : '') +            '</div>';        semestersList.innerHTML = html;        semestersModal.classList.add('active');        document.body.style.overflow = 'hidden';    };    window.activateCodeFromTeacher = async function() {        var codeInput = document.getElementById('codeInputTeacher');        var codeMessage = document.getElementById('codeMessageTeacher');        var code = codeInput.value.trim().toUpperCase();        if (!code) {            codeMessage.innerHTML = '⚠️ يرجى إدخال الكود';            codeMessage.style.color = '#f59e0b';            return;        }        if (!activeTeacher) {            codeMessage.innerHTML = '⚠️ يرجى اختيار مدرس أولاً';            codeMessage.style.color = '#f59e0b';            return;        }        if (!currentUser) {            codeMessage.innerHTML = '⚠️ يجب تسجيل الدخول أولاً';            codeMessage.style.color = '#ef4444';            showToast('error', '⚠️ يجب تسجيل الدخول أولاً');            return;        }        var result = await verifyCode(activeTeacher, code);        codeMessage.innerHTML = result.message;        codeMessage.style.color = result.valid ? '#22c55e' : '#ef4444';        if (result.valid) {            showToast('success', '✅ تم التفعيل بنجاح!');            renderAllData();            renderMyCourses();            renderAccount();            updateBadge();            updateUserCodesStorage();            setTimeout(function() {                if (activeSectionIndex !== null && activeTeacherIndex !== null) {                    openTeacher(activeSectionIndex, activeTeacherIndex);                }            }, 1500);        } else {            showToast('error', '❌ ' + result.message);        }    };    window.openLectures = function(sectionIndex, teacherIndex, semesterIndex) {        var section = data.sections[sectionIndex];        if (!section) return;        var teacher = section.teachers[teacherIndex];        if (!teacher) return;        var semester = teacher.semesters[semesterIndex];        if (!semester) return;        var hasAccess = hasAccessToTeacher(teacher);        modalSemesterTitle.textContent = '📖 الفصل ' + semester.number + ' - ' + teacher.name;        var html = '';        var lectures = Array.isArray(semester.lectures) ? semester.lectures : [];        lectures.forEach(function(lecture, li) {            var isFree = lecture.isFree === true;            var canWatch = isFree || hasAccess;            var videoUrl = lecture.youtubeUrl || '';            var isMediaDelivery = videoUrl.includes('mediadelivery');            var isDynTube = videoUrl.includes('dyntube.com') || videoUrl.includes('videos.dyntube.com');            var videoIcon = isMediaDelivery ? 'fa-video' : (isDynTube ? 'fa-film' : 'fa-play-circle');            var watched = isLectureWatched(teacher.id, semesterIndex, li);            html +=                '<div class="lecture-item ' + (canWatch ? '' : 'locked') + '" onclick="' + (canWatch ? 'playVideo(\'' + videoUrl + '\', \'' + lecture.title + '\', \'' + teacher.id + '\', ' + semesterIndex + ', ' + li + ')' : '') + '">' +                '<div class="lecture-number">#' + lecture.number + '</div>' +                '<div class="lecture-title">' + lecture.title + (watched ? ' ✅' : '') + '</div>' +                '<div class="lecture-status">' +                (isFree ? '<span class="free-badge">🆓 مجانية</span>' : '') +                (isMediaDelivery ? '<span style="font-size:0.5rem;color:var(--primary);margin-left:0.2rem;">📹</span>' : '') +                (isDynTube ? '<span style="font-size:0.5rem;color:var(--secondary);margin-left:0.2rem;">🎬</span>' : '') +                (watched ? '<span style="color:var(--success);font-size:0.5rem;">✅</span>' : '') +                (canWatch ? '<i class="fas ' + videoIcon + '" style="color:var(--primary);"></i>' : '<i class="fas fa-lock" style="color:#ef4444;"></i>') +                '</div>' +                '</div>';        });        lecturesList.innerHTML = html;        lecturesModal.classList.add('active');        document.body.style.overflow = 'hidden';    };    // ============================================================    // دوراتي    // ============================================================    function getMyCourses() {        if (!currentUser) return [];        var courses = [];        data.sections.forEach(function(section) {            section.teachers.forEach(function(teacher, teacherIndex) {                if (teacher.codes) {                    var hasAccess = teacher.codes.some(function(c) { return c.used && c.userEmail === currentUser.email && !c                        .locked; });                    if (hasAccess) {                        if (!teacher.id) {                            teacher.id = 'teacher_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);                        }                        var totalLectures = 0;                        var completedLectures = 0;                        if (teacher.semesters) {                            teacher.semesters.forEach(function(semester, si) {                                if (semester.lectures) {                                    semester.lectures.forEach(function(lecture, li) {                                        totalLectures++;                                        if (isLectureWatched(teacher.id, si, li)) {                                            completedLectures++;                                        }                                    });                                }                            });                        }                        var progress = totalLectures > 0 ? Math.round((completedLectures / totalLectures) * 100) :                            0;                        courses.push({                            teacherName: teacher.name,                            teacherEmoji: teacher.emoji || '👨‍🏫',                            teacherImage: teacher.image || '',                            sectionName: section.name,                            sectionIndex: data.sections.indexOf(section),                            teacherIndex: teacherIndex,                            teacherId: teacher.id,                            codes: teacher.codes.filter(function(c) { return c.used && c.userEmail === currentUser                                    .email; }),                            totalLectures: totalLectures,                            completedLectures: completedLectures,                            progress: progress                        });                    }                }            });        });        return courses;    }    function renderMyCourses() {        var container = document.getElementById('myCoursesContainer');        var countSpan = document.getElementById('myCoursesCount');        if (!container) return;        var courses = getMyCourses();        if (countSpan) countSpan.textContent = courses.length + ' دورة';        if (courses.length === 0) {            container.innerHTML =                '<div class="empty-courses">' +                '<span class="empty-icon">📚</span>' +                '<h3>لم تشترك في أي دورة بعد</h3>' +                '<p>استخدم كود التفعيل للاشتراك في دورات المدرسين</p>' +                '<button class="btn-primary" onclick="navigateTo(\'teachers\')">' +                '<i class="fas fa-search"></i> استعراض المدرسين' +                '</button>' +                '</div>';            return;        }        var totalLectures = 0;        var completedLectures = 0;        courses.forEach(function(course) {            totalLectures += course.totalLectures || 0;            completedLectures += course.completedLectures || 0;        });        var overallProgress = totalLectures > 0 ? Math.round((completedLectures / totalLectures) * 100) : 0;        var progressFill = document.getElementById('overallProgress');        var progressPercentage = document.getElementById('progressPercentage');        if (progressFill) progressFill.style.width = overallProgress + '%';        if (progressPercentage) progressPercentage.textContent = overallProgress + '%';        var html = '<div class="my-courses-grid">';        courses.forEach(function(course) {            var progress = course.progress || 0;            html +=                '<div class="course-card-mini" onclick="openTeacher(' + course.sectionIndex + ', ' + course.teacherIndex + ')">' +                '<div class="course-avatar">' +                (course.teacherImage ? '<img src="' + course.teacherImage + '" />' : course.teacherEmoji) +                '</div>' +                '<div class="course-name">' + course.teacherName + '</div>' +                '<div class="course-meta">' + course.sectionName + ' | ' + course.codes.length + ' كود</div>' +                '<div class="course-badge">✅ مشترك</div>' +                '<div class="course-progress">' +                '<div class="mini-bar">' +                '<div class="mini-fill" style="width:' + progress + '%;"></div>' +                '</div>' +                '<span class="mini-label">' + progress + '% مكتمل</span>' +                '</div>' +                '</div>';        });        html += '</div>';        container.innerHTML = html;    }    // ============================================================    // الحساب الشخصي    // ============================================================    function renderAccount() {        if (!currentUser) {            accountName.textContent = 'غير مسجل';            accountEmail.textContent = 'يرجى تسجيل الدخول';            accountAvatar.textContent = '👤';            accountRegistered.textContent = '--';            accountCourses.textContent = '0';            accountCodes.textContent = '0';            accountProgress.textContent = '0%';            accountLectures.textContent = '0';            if (adminPanelBtn) adminPanelBtn.style.display = 'none';            return;        }        var name = currentUser.user_metadata?.full_name || currentUser.email?.split('@')[0] || 'مستخدم';        accountName.textContent = name;        accountEmail.textContent = currentUser.email;        accountAvatar.textContent = name.charAt(0).toUpperCase();        var registered = currentUser.created_at ? new Date(currentUser.created_at).toLocaleDateString('ar') : 'غير معروف';        accountRegistered.textContent = 'مسجل منذ: ' + registered;        var courses = getMyCourses();        accountCourses.textContent = courses.length;        var codesCount = 0;        var totalLectures = 0;        var completedLectures = 0;        data.sections.forEach(function(section) {            section.teachers.forEach(function(teacher) {                if (teacher.codes) {                    codesCount += teacher.codes.filter(function(c) { return c.used && c.userEmail === currentUser                            .email; }).length;                }                if (teacher.semesters) {                    if (!teacher.id) {                        teacher.id = 'teacher_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);                    }                    teacher.semesters.forEach(function(semester, si) {                        if (semester.lectures) {                            semester.lectures.forEach(function(lecture, li) {                                totalLectures++;                                if (isLectureWatched(teacher.id, si, li)) {                                    completedLectures++;                                }                            });                        }                    });                }            });        });        accountCodes.textContent = codesCount;        accountLectures.textContent = completedLectures;        var progress = totalLectures > 0 ? Math.round((completedLectures / totalLectures) * 100) : 0;        accountProgress.textContent = progress + '%';        checkIsAdmin(currentUser.email).then(function(isAdmin) {            if (adminPanelBtn) {                adminPanelBtn.style.display = isAdmin ? 'flex' : 'none';                if (isAdmin) {                    console.log('👑 مرحباً أيها المشرف! زر الإدارة ظاهر');                }            }        });    }    function updateBadge() {        var courses = getMyCourses();        if (courses.length > 0) {            if (coursesBadge) { coursesBadge.style.display = 'inline';                coursesBadge.textContent = courses.length; }            if (coursesBadgeMobile) { coursesBadgeMobile.style.display = 'inline';                coursesBadgeMobile.textContent = courses.length; }        } else {            if (coursesBadge) coursesBadge.style.display = 'none';            if (coursesBadgeMobile) coursesBadgeMobile.style.display = 'none';        }    }    // ============================================================    // تسجيل الخروج    // ============================================================    async function signOut() {        try {            localStorage.removeItem('devAcademicUser');            if (supabaseClient) {                await supabaseClient.auth.signOut();            }            currentUser = null;            activeTeacher = null;            activeTeacherIndex = null;            activeSectionIndex = null;            updateUI();            if (adminPanel) adminPanel.classList.remove('open');            if (adminOverlay) adminOverlay.classList.remove('show');            if (semestersModal) semestersModal.classList.remove('active');            if (lecturesModal) lecturesModal.classList.remove('active');            if (teachersModal) teachersModal.classList.remove('active');            if (deleteAccountModal) deleteAccountModal.classList.remove('active');            if (studentProgressModal) studentProgressModal.classList.remove('active');            renderMyCourses();            renderAccount();            updateBadge();            renderAllData();            showToast('success', '✅ تم تسجيل الخروج بنجاح');            setTimeout(function() {                window.location.href = 'index.html';            }, 800);        } catch (error) {            console.warn('SignOut exception:', error);            showToast('error', '❌ حدث خطأ أثناء تسجيل الخروج');        }    }    // ============================================================    // حذف الحساب    // ============================================================    window.confirmDeleteAccount = async function() {        var password = deletePasswordInput.value;        if (!password) {            deleteAccountMessage.innerHTML = '⚠️ يرجى إدخال كلمة المرور';            deleteAccountMessage.style.color = '#f59e0b';            return;        }        if (!supabaseClient) {            deleteAccountMessage.innerHTML = '❌ الخدمة غير متوفرة';            deleteAccountMessage.style.color = '#ef4444';            return;        }        try {            var signInResult = await supabaseClient.auth.signInWithPassword({                email: currentUser.email,                password: password            });            if (signInResult.error) {                deleteAccountMessage.innerHTML = '❌ كلمة المرور غير صحيحة';                deleteAccountMessage.style.color = '#ef4444';                return;            }            var deleteUserResult = await supabaseClient                .from('users')                .delete()                .eq('email', currentUser.email);            if (deleteUserResult.error) {                console.warn('⚠️ فشل حذف المستخدم من جدول users:', deleteUserResult.error);            }            var deleteAdminResult = await supabaseClient                .from('admins')                .delete()                .eq('email', currentUser.email);            if (deleteAdminResult.error) {                console.warn('⚠️ فشل حذف المستخدم من جدول admins:', deleteAdminResult.error);            }            var userCodesResult = await supabaseClient                .from('user_codes')                .delete()                .eq('user_id', currentUser.id);            if (userCodesResult.error) {                console.warn('⚠️ فشل حذف الأكواد المرتبطة:', userCodesResult.error);            }            var teacherCodesResult = await supabaseClient                .from('teacher_codes')                .delete()                .eq('user_id', currentUser.id);            if (teacherCodesResult.error) {                console.warn('⚠️ فشل حذف الكود من teacher_codes:', teacherCodesResult.error);            }            try {                await supabaseClient.auth.admin.deleteUser(currentUser.id);            } catch (authError) {                console.warn('⚠️ فشل حذف المستخدم من Auth:', authError);                await supabaseClient.auth.signOut();            }            localStorage.removeItem('devAcademicUser');            localStorage.removeItem('academyData');            localStorage.removeItem('userCodes_' + currentUser.email);            localStorage.removeItem('deviceId');            localStorage.removeItem('studentProgress_' + currentUser.id);            showToast('success', '✅ تم حذف الحساب بنجاح');            deleteAccountMessage.innerHTML = '✅ تم حذف الحساب بنجاح، جارِ التوجيه...';            deleteAccountMessage.style.color = '#22c55e';            setTimeout(function() {                window.location.href = 'index.html';            }, 1500);        } catch (error) {            console.error('Delete account error:', error);            deleteAccountMessage.innerHTML = '❌ حدث خطأ: ' + error.message;            deleteAccountMessage.style.color = '#ef4444';        }    };    // ============================================================    // تحديث واجهة المستخدم    // ============================================================    function updateUI() {        if (currentUser) {            var name = currentUser.user_metadata?.full_name || currentUser.email?.split('@')[0] || 'مستخدم';            userNameDisplay.textContent = name;            userAvatar.textContent = name.charAt(0).toUpperCase();        } else {            userNameDisplay.textContent = 'غير مسجل';            userAvatar.textContent = '👤';        }    }    // ============================================================    // التنقل بين الصفحات    // ============================================================    window.navigateTo = function(page) {        if (!currentUser) {            window.location.href = 'index.html';            return;        }        document.querySelectorAll('.page-content').forEach(function(p) { p.style.display = 'none'; });        var targetPage = document.getElementById('page-' + page);        if (targetPage) targetPage.style.display = 'block';        document.querySelectorAll('.nav-links li').forEach(function(l) { l.classList.remove('active'); });        var navLink = document.querySelector('.nav-links li a[onclick*="' + page + '"]');        if (navLink) navLink.closest('li')?.classList.add('active');        document.querySelectorAll('.bottom-nav .nav-item').forEach(function(item) {            item.classList.toggle('active', item.dataset.page === page);        });        var hero = document.getElementById('hero');        if (hero) {            hero.style.display = page === 'home' ? 'flex' : 'none';        }        if (page === 'my-courses') {            renderMyCourses();            updateBadge();        }        if (page === 'account') {            renderAccount();        }        if (page === 'teachers' || page === 'home') {            renderAllData();        }        window.scrollTo({ top: 0, behavior: 'smooth' });    };    // ============================================================    // أحداث التنقل    // ============================================================    document.querySelectorAll('[data-page]').forEach(function(link) {        link.addEventListener('click', function(e) {            e.preventDefault();            navigateTo(this.dataset.page);        });    });    document.querySelectorAll('.bottom-nav .nav-item').forEach(function(item) {        item.addEventListener('click', function() {            navigateTo(this.dataset.page);        });    });    // ============================================================    // زر الملف الشخصي    // ============================================================    var userProfileBtn = document.getElementById('userProfileBtn');    if (userProfileBtn) {        userProfileBtn.addEventListener('click', function() {            if (!currentUser) {                window.location.href = 'index.html';                return;            }            navigateTo('account');        });    }    // ============================================================    // تسجيل الخروج - زر الحساب    // ============================================================    if (logoutAccountBtn) {        logoutAccountBtn.addEventListener('click', signOut);    }    // ============================================================    // حذف الحساب - زر الفتح    // ============================================================    if (deleteAccountBtn) {        deleteAccountBtn.addEventListener('click', function() {            if (!currentUser) {                showToast('warning', '⚠️ يجب تسجيل الدخول أولاً');                return;            }            deleteAccountModal.classList.add('active');            deletePasswordInput.value = '';            deleteAccountMessage.innerHTML = '';            document.body.style.overflow = 'hidden';        });    }    if (closeDeleteModal) {        closeDeleteModal.addEventListener('click', function() {            deleteAccountModal.classList.remove('active');            document.body.style.overflow = 'auto';            deletePasswordInput.value = '';            deleteAccountMessage.innerHTML = '';        });    }    if (deleteAccountModal) {        deleteAccountModal.addEventListener('click', function(e) {            if (e.target === this) {                deleteAccountModal.classList.remove('active');                document.body.style.overflow = 'auto';                deletePasswordInput.value = '';                deleteAccountMessage.innerHTML = '';            }        });    }    // ============================================================    // لوحة التحكم    // ============================================================    if (adminPanelBtn) {        adminPanelBtn.addEventListener('click', function() {            if (!currentUser) {                showToast('warning', '⚠️ يرجى تسجيل الدخول أولاً');                return;            }            checkIsAdmin(currentUser.email).then(function(isAdmin) {                if (isAdmin) {                    openAdminPanel();                } else {                    showToast('error', '❌ غير مصرح لك بالدخول إلى لوحة التحكم');                }            });        });    }    if (adminClose) {        adminClose.addEventListener('click', function() {            closeAdminPanel();        });    }    if (adminOverlay) {        adminOverlay.addEventListener('click', function() {            closeAdminPanel();        });    }    // ============================================================    // دوال فتح وإغلاق لوحة الإدارة    // ============================================================    function openAdminPanel() {        var panel = document.getElementById('adminPanel');        var overlay = document.getElementById('adminOverlay');        if (panel) panel.classList.add('open');        if (overlay) overlay.classList.add('show');        if (typeof updateAllAdminSelects === 'function') updateAllAdminSelects();        if (typeof updatePendingChanges === 'function') updatePendingChanges();        if (typeof loadAdminsList === 'function') loadAdminsList();        if (typeof renderUsersTable === 'function') renderUsersTable();        if (typeof renderSectionsList === 'function') renderSectionsList();        if (typeof renderTeachersListAdmin === 'function') renderTeachersListAdmin();        if (typeof renderSemestersListAdmin === 'function') renderSemestersListAdmin();        if (typeof renderLecturesListAdmin === 'function') renderLecturesListAdmin();        if (typeof filterStudents === 'function') filterStudents();        showAdminTab('dashboard');        showToast('success', '🔓 مرحباً بك في لوحة التحكم');    }    function closeAdminPanel() {        var panel = document.getElementById('adminPanel');        var overlay = document.getElementById('adminOverlay');        if (panel) panel.classList.remove('open');        if (overlay) overlay.classList.remove('show');    }    // ============================================================    // إظهار التبويب النشط    // ============================================================    function showAdminTab(tabId) {        document.querySelectorAll('.tab-content').forEach(function(tab) {            tab.classList.remove('active');        });        var targetTab = document.getElementById('tab-' + tabId);        if (targetTab) {            targetTab.classList.add('active');        }        document.querySelectorAll('.admin-tabs .tab-btn').forEach(function(btn) {            btn.classList.remove('active');            if (btn.dataset.tab === tabId) {                btn.classList.add('active');            }        });    }    // ============================================================    // أحداث التبويبات    // ============================================================    document.querySelectorAll('.admin-tabs .tab-btn').forEach(function(btn) {        btn.addEventListener('click', function(e) {            e.preventDefault();            e.stopPropagation();            var tabId = this.dataset.tab;            showAdminTab(tabId);            if (tabId === 'codes' || tabId === 'manage-codes') {                if (typeof updateAllAdminSelects === 'function') updateAllAdminSelects();                if (typeof updateCodesManagement === 'function') updateCodesManagement();            }            if (tabId === 'sections') {                if (typeof updateAllAdminSelects === 'function') updateAllAdminSelects();                if (typeof renderSectionsList === 'function') renderSectionsList();            }            if (tabId === 'teachers') {                if (typeof updateAllAdminSelects === 'function') updateAllAdminSelects();                if (typeof renderTeachersListAdmin === 'function') renderTeachersListAdmin();            }            if (tabId === 'semesters') {                if (typeof updateAllAdminSelects === 'function') updateAllAdminSelects();                if (typeof renderSemestersListAdmin === 'function') renderSemestersListAdmin();            }            if (tabId === 'lectures') {                if (typeof updateAllAdminSelects === 'function') updateAllAdminSelects();                if (typeof renderLecturesListAdmin === 'function') renderLecturesListAdmin();            }            if (tabId === 'edit-lecture') {                if (typeof updateAllAdminSelects === 'function') updateAllAdminSelects();                if (typeof renderEditLectureList === 'function') renderEditLectureList();            }            if (tabId === 'students') {                if (typeof updateAllAdminSelects === 'function') updateAllAdminSelects();                if (typeof filterStudents === 'function') filterStudents();            }            if (tabId === 'users') {                if (typeof renderUsersTable === 'function') renderUsersTable();            }            if (tabId === 'admins') {                if (typeof loadAdminsList === 'function') loadAdminsList();            }            if (tabId === 'settings') {                var savedBanner = localStorage.getItem('bannerImage');                if (savedBanner) {                    var img = document.getElementById('bannerImage');                    var placeholder = document.getElementById('bannerPlaceholder');                    if (img) { img.src = savedBanner;                        img.style.display = 'block'; }                    if (placeholder) placeholder.style.display = 'none';                    var urlInput = document.getElementById('bannerUrlInput');                    if (urlInput) urlInput.value = savedBanner;                }                var darkModeToggle = document.getElementById('darkModeToggle');                if (darkModeToggle) darkModeToggle.checked = isDarkMode;            }            if (tabId === 'dashboard') {                if (typeof renderAllData === 'function') renderAllData();            }        });    });    // ============================================================    // الوضع المظلم    // ============================================================    function toggleTheme() {        isDarkMode = !isDarkMode;        document.body.classList.toggle('dark-mode', isDarkMode);        themeToggle.innerHTML = isDarkMode ? '<i class="fas fa-sun"></i>' : '<i class="fas fa-moon"></i>';        localStorage.setItem('devAcademicTheme', isDarkMode ? 'dark' : 'light');        showToast('info', isDarkMode ? '🌙 تم تفعيل الوضع المظلم' : '☀️ تم تفعيل الوضع الفاتح');        var darkModeToggle = document.getElementById('darkModeToggle');        if (darkModeToggle) darkModeToggle.checked = isDarkMode;    }    window.toggleTheme = toggleTheme;    if (themeToggle) {        themeToggle.addEventListener('click', toggleTheme);    }    // ============================================================    // البحث    // ============================================================    function applyFilters() {        var term = searchInput.value.trim().toLowerCase();        if (term === '') {            renderAllData();            return;        }        var allTeachers = getAllTeachers();        var filtered = allTeachers.filter(function(t) {            return t.name.toLowerCase().includes(term) ||                (t.subject && t.subject.toLowerCase().includes(term)) ||                (t.description && t.description.toLowerCase().includes(term)) ||                (t._sectionName && t._sectionName.toLowerCase().includes(term));        });        renderTeachers(filtered, teachersGridContainer);        renderTeachers(filtered, teachersGridContainer2);    }    if (searchBtn) {        searchBtn.addEventListener('click', applyFilters);    }    if (searchInput) {        searchInput.addEventListener('keyup', function(e) {            if (e.key === 'Enter') applyFilters();        });    }    // ============================================================    // إغلاق النوافذ المنبثقة    // ============================================================    function closeModal(modal) {        modal.classList.remove('active');        document.body.style.overflow = 'auto';    }    if (closeTeachersModal) {        closeTeachersModal.addEventListener('click', function() { closeModal(teachersModal); });    }    if (closeSemestersModal) {        closeSemestersModal.addEventListener('click', function() { closeModal(semestersModal); });    }    if (closeLecturesModal) {        closeLecturesModal.addEventListener('click', function() { closeModal(lecturesModal); });    }    if (teachersModal) {        teachersModal.addEventListener('click', function(e) {            if (e.target === this) closeModal(this);        });    }    if (semestersModal) {        semestersModal.addEventListener('click', function(e) {            if (e.target === this) closeModal(this);        });    }    if (lecturesModal) {        lecturesModal.addEventListener('click', function(e) {            if (e.target === this) closeModal(this);        });    }    // ============================================================    // مشغل الفيديو    // ============================================================    if (closePlayer) {        closePlayer.addEventListener('click', closeVideoPlayer);    }    if (videoPlayer) {        videoPlayer.addEventListener('click', function(e) {            if (e.target === this) closeVideoPlayer();        });    }    document.addEventListener('keydown', function(e) {        if (e.key === 'Escape') {            if (videoPlayer && videoPlayer.classList.contains('active')) closeVideoPlayer();            if (teachersModal && teachersModal.classList.contains('active')) closeModal(teachersModal);            if (semestersModal && semestersModal.classList.contains('active')) closeModal(semestersModal);            if (lecturesModal && lecturesModal.classList.contains('active')) closeModal(lecturesModal);            if (studentProgressModal && studentProgressModal.classList.contains('active')) {                studentProgressModal.classList.remove('active');                document.body.style.overflow = 'auto';            }            if (deleteAccountModal && deleteAccountModal.classList.contains('active')) {                deleteAccountModal.classList.remove('active');                document.body.style.overflow = 'auto';            }            if (adminPanel && adminPanel.classList.contains('open')) closeAdminPanel();        }    });    // ============================================================    // دوال إدارة الأقسام والمدرسين والفصول والمحاضرات    // ============================================================    function updateAllAdminSelects() {        updateBasicSelects();        updateTeacherSelects();        updateSemesterSelects();        updateCodeSelects();        updateCodesManagement();        updateEditTeacherData();        updateStudentFilters();        updateEditLectureSelects();    }    function updateBasicSelects() {        var selectIds = [            'teacherSection', 'lectureSection', 'semesterSection',            'codeSection', 'editTeacherSection', 'editLectureSection',            'deleteTeacherSection', 'deleteSemesterSection',            'deleteLectureSection', 'codeTeacherSelect',            'lectureTeacher', 'lectureSemester',            'studentSectionFilter', 'studentTeacherFilter',            'editLectureTeacher', 'editLectureSemester', 'editLectureSelect',            'deleteSemesterTeacher', 'deleteSemesterSelect',            'deleteLectureTeacher', 'deleteLectureSemester', 'deleteLectureSelect',            'semesterTeacher'        ];        selectIds.forEach(function(id) {            var select = document.getElementById(id);            if (!select) return;            var currentValue = select.value;            var options = '<option value="">اختر...</option>';            if (id === 'studentSectionFilter' || id === 'studentTeacherFilter') {                options = '<option value="all">الكل</option>';                data.sections.forEach(function(s, i) {                    options += '<option value="' + i + '">' + s.name + '</option>';                });            } else {                data.sections.forEach(function(s, i) {                    options += '<option value="' + i + '">' + s.name + '</option>';                });            }            select.innerHTML = options;            if (currentValue && data.sections[parseInt(currentValue)]) {                select.value = currentValue;            }            if (currentValue === 'all' && (id === 'studentSectionFilter' || id === 'studentTeacherFilter')) {                select.value = 'all';            }        });    }    function updateTeacherSelects() {        var teacherSelects = [            { selectId: 'lectureTeacher', sectionId: 'lectureSection' },            { selectId: 'codeTeacherSelect', sectionId: 'codeSection' },            { selectId: 'editTeacherSelect', sectionId: 'editTeacherSection' },            { selectId: 'editLectureTeacher', sectionId: 'editLectureSection' },            { selectId: 'deleteTeacherSelect', sectionId: 'deleteTeacherSection' },            { selectId: 'deleteSemesterTeacher', sectionId: 'deleteSemesterSection' },            { selectId: 'deleteLectureTeacher', sectionId: 'deleteLectureSection' },            { selectId: 'semesterTeacher', sectionId: 'semesterSection' }        ];        teacherSelects.forEach(function(item) {            var select = document.getElementById(item.selectId);            var sectionSelect = document.getElementById(item.sectionId);            if (!select || !sectionSelect) return;            var sectionIndex = parseInt(sectionSelect.value);            var currentValue = select.value;            var options = '<option value="">اختر...</option>';            if (!isNaN(sectionIndex) && sectionIndex >= 0 && data.sections[sectionIndex]) {                data.sections[sectionIndex].teachers.forEach(function(t, i) {                    options += '<option value="' + i + '">' + t.name + '</option>';                });            }            select.innerHTML = options;            if (currentValue && !isNaN(sectionIndex) && sectionIndex >= 0 &&                data.sections[sectionIndex]?.teachers[parseInt(currentValue)]) {                select.value = currentValue;            }        });    }    function updateSemesterSelects() {        var semesterSelects = [            { selectId: 'lectureSemester', teacherId: 'lectureTeacher', sectionId: 'lectureSection' },            { selectId: 'deleteSemesterSelect', teacherId: 'deleteSemesterTeacher', sectionId: 'deleteSemesterSection' },            { selectId: 'deleteLectureSemester', teacherId: 'deleteLectureTeacher', sectionId: 'deleteLectureSection' },            { selectId: 'editLectureSemester', teacherId: 'editLectureTeacher', sectionId: 'editLectureSection' }        ];        semesterSelects.forEach(function(item) {            var select = document.getElementById(item.selectId);            var teacherSelect = document.getElementById(item.teacherId);            var sectionSelect = document.getElementById(item.sectionId);            if (!select || !teacherSelect || !sectionSelect) return;            var sectionIndex = parseInt(sectionSelect.value);            var teacherIndex = parseInt(teacherSelect.value);            var currentValue = select.value;            var options = '<option value="">اختر...</option>';            if (!isNaN(sectionIndex) && sectionIndex >= 0 &&                !isNaN(teacherIndex) && teacherIndex >= 0 &&                data.sections[sectionIndex]?.teachers[teacherIndex]) {                var teacher = data.sections[sectionIndex].teachers[teacherIndex];                if (teacher.semesters) {                    teacher.semesters.forEach(function(s, i) {                        options += '<option value="' + i + '">الفصل ' + s.number + ' - ' + (s.description || '') +                            '</option>';                    });                }            }            select.innerHTML = options;            if (currentValue && !isNaN(sectionIndex) && sectionIndex >= 0 &&                !isNaN(teacherIndex) && teacherIndex >= 0 &&                data.sections[sectionIndex]?.teachers[teacherIndex]?.semesters[parseInt(currentValue)]) {                select.value = currentValue;            }        });        updateLectureSelects();    }    function updateLectureSelects() {        var lectureSelects = [            { selectId: 'editLectureSelect', semesterId: 'editLectureSemester', sectionId: 'editLectureSection',                teacherId: 'editLectureTeacher' },            { selectId: 'deleteLectureSelect', semesterId: 'deleteLectureSemester', sectionId: 'deleteLectureSection',                teacherId: 'deleteLectureTeacher' }        ];        lectureSelects.forEach(function(item) {            var select = document.getElementById(item.selectId);            var semesterSelect = document.getElementById(item.semesterId);            var sectionSelect = document.getElementById(item.sectionId);            var teacherSelect = document.getElementById(item.teacherId);            if (!select || !semesterSelect || !sectionSelect || !teacherSelect) return;            var sectionIndex = parseInt(sectionSelect.value);            var teacherIndex = parseInt(teacherSelect.value);            var semesterIndex = parseInt(semesterSelect.value);            var currentValue = select.value;            var options = '<option value="">اختر...</option>';            if (!isNaN(sectionIndex) && sectionIndex >= 0 &&                !isNaN(teacherIndex) && teacherIndex >= 0 &&                !isNaN(semesterIndex) && semesterIndex >= 0 &&                data.sections[sectionIndex]?.teachers[teacherIndex]?.semesters[semesterIndex]?.lectures) {                var lectures = data.sections[sectionIndex].teachers[teacherIndex].semesters[semesterIndex].lectures;                lectures.forEach(function(l, i) {                    options += '<option value="' + i + '">#' + l.number + ' - ' + l.title + '</option>';                });            }            select.innerHTML = options;            if (currentValue && !isNaN(sectionIndex) && sectionIndex >= 0 &&                !isNaN(teacherIndex) && teacherIndex >= 0 &&                !isNaN(semesterIndex) && semesterIndex >= 0 &&                data.sections[sectionIndex]?.teachers[teacherIndex]?.semesters[semesterIndex]?.lectures[parseInt(                    currentValue)]) {                select.value = currentValue;            }        });    }    function updateEditLectureSelects() {        // تحديث قوائم تعديل المحاضرة        var sectionSelect = document.getElementById('editLectureSection');        var teacherSelect = document.getElementById('editLectureTeacher');        var semesterSelect = document.getElementById('editLectureSemester');        var lectureSelect = document.getElementById('editLectureSelect');        if (sectionSelect && teacherSelect && semesterSelect && lectureSelect) {            var sectionIndex = parseInt(sectionSelect.value);            var teacherIndex = parseInt(teacherSelect.value);            var semesterIndex = parseInt(semesterSelect.value);            var currentValue = lectureSelect.value;            var options = '<option value="">اختر...</option>';            if (!isNaN(sectionIndex) && sectionIndex >= 0 &&                !isNaN(teacherIndex) && teacherIndex >= 0 &&                !isNaN(semesterIndex) && semesterIndex >= 0 &&                data.sections[sectionIndex]?.teachers[teacherIndex]?.semesters[semesterIndex]?.lectures) {                var lectures = data.sections[sectionIndex].teachers[teacherIndex].semesters[semesterIndex].lectures;                lectures.forEach(function(l, i) {                    options += '<option value="' + i + '">#' + l.number + ' - ' + l.title + '</option>';                });            }            lectureSelect.innerHTML = options;            if (currentValue && !isNaN(sectionIndex) && sectionIndex >= 0 &&                !isNaN(teacherIndex) && teacherIndex >= 0 &&                !isNaN(semesterIndex) && semesterIndex >= 0 &&                data.sections[sectionIndex]?.teachers[teacherIndex]?.semesters[semesterIndex]?.lectures[parseInt(                    currentValue)]) {                lectureSelect.value = currentValue;            }        }    }    function updateCodeSelects() {        var sectionSelect = document.getElementById('codeSection');        var teacherSelect = document.getElementById('codeTeacherSelect');        if (!sectionSelect || !teacherSelect) return;        var sectionIndex = parseInt(sectionSelect.value);        var currentValue = teacherSelect.value;        var options = '<option value="">اختر...</option>';        if (!isNaN(sectionIndex) && sectionIndex >= 0 && data.sections[sectionIndex]) {            data.sections[sectionIndex].teachers.forEach(function(t, i) {                options += '<option value="' + i + '">' + t.name + '</option>';            });        }        teacherSelect.innerHTML = options;        if (currentValue && !isNaN(sectionIndex) && sectionIndex >= 0 &&            data.sections[sectionIndex]?.teachers[parseInt(currentValue)]) {            teacherSelect.value = currentValue;        }    }    function updateEditTeacherData() {        var sectionSelect = document.getElementById('editTeacherSection');        var teacherSelect = document.getElementById('editTeacherSelect');        if (!sectionSelect || !teacherSelect) return;        var sectionIndex = parseInt(sectionSelect.value);        var teacherIndex = parseInt(teacherSelect.value);        if (isNaN(sectionIndex) || sectionIndex < 0 || isNaN(teacherIndex) || teacherIndex < 0 ||            !data.sections[sectionIndex]?.teachers[teacherIndex]) {            var nameInput = document.getElementById('editTeacherName');            var subjectInput = document.getElementById('editTeacherSubject');            var descInput = document.getElementById('editTeacherDesc');            var imageInput = document.getElementById('editTeacherImage');            if (nameInput) nameInput.value = '';            if (subjectInput) subjectInput.value = '';            if (descInput) descInput.value = '';            if (imageInput) imageInput.value = '';            return;        }        var teacher = data.sections[sectionIndex].teachers[teacherIndex];        var nameInput = document.getElementById('editTeacherName');        var subjectInput = document.getElementById('editTeacherSubject');        var descInput = document.getElementById('editTeacherDesc');        var imageInput = document.getElementById('editTeacherImage');        if (nameInput) nameInput.value = teacher.name || '';        if (subjectInput) subjectInput.value = teacher.subject || '';        if (descInput) descInput.value = teacher.description || '';        if (imageInput) imageInput.value = teacher.image || '';        var msg = document.getElementById('editTeacherMessage');        if (msg) msg.innerHTML = '';    }    function updateStudentFilters() {        var sectionFilter = document.getElementById('studentSectionFilter');        var teacherFilter = document.getElementById('studentTeacherFilter');        if (!sectionFilter || !teacherFilter) return;        var sectionIndex = parseInt(sectionFilter.value);        var currentTeacherValue = teacherFilter.value;        var options = '<option value="all">جميع المدرسين</option>';        if (!isNaN(sectionIndex) && sectionIndex >= 0 && data.sections[sectionIndex]) {            data.sections[sectionIndex].teachers.forEach(function(t, i) {                options += '<option value="' + i + '">' + t.name + '</option>';            });        }        teacherFilter.innerHTML = options;        if (currentTeacherValue !== 'all' && !isNaN(sectionIndex) && sectionIndex >= 0 &&            data.sections[sectionIndex]?.teachers[parseInt(currentTeacherValue)]) {            teacherFilter.value = currentTeacherValue;        }    }    function updatePendingChanges() {        if (pendingChangesSpan) pendingChangesSpan.textContent = pendingChanges;    }    function addChange() {        pendingChanges++;        updatePendingChanges();    }    // ============================================================    // دوال إضافة الأقسام والمدرسين والفصول والمحاضرات    // ============================================================    window.addSection = function() {        var nameInput = document.getElementById('sectionName');        var name = nameInput.value.trim();        if (!name) {            showToast('warning', '⚠️ يرجى إدخال اسم القسم');            return;        }        var newSection = {            id: 'sec-' + Date.now() + '-' + Math.random().toString(36).substr(2, 6),            name: name,            teachers: []        };        data.sections.push(newSection);        saveData();        renderAllData();        updateAllAdminSelects();        addChange();        nameInput.value = '';        showToast('success', '✅ تم إضافة القسم "' + name + '" بنجاح');        renderSectionsList();    };    window.addTeacher = function() {        var sectionSelect = document.getElementById('teacherSection');        var sectionIndex = parseInt(sectionSelect?.value);        if (isNaN(sectionIndex) || sectionIndex < 0) {            showToast('warning', '⚠️ يرجى اختيار القسم');            return;        }        var nameInput = document.getElementById('teacherName');        var emojiInput = document.getElementById('teacherEmoji');        var subjectInput = document.getElementById('teacherSubject');        var imageInput = document.getElementById('teacherImage');        var name = nameInput.value.trim();        var emoji = emojiInput.value.trim() || '🧑‍🏫';        var subject = subjectInput.value.trim();        var image = imageInput.value.trim();        if (!name) {            showToast('warning', '⚠️ يرجى إدخال اسم المدرس');            return;        }        var newTeacher = {            id: 'teacher_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6),            name: name,            emoji: emoji,            subject: subject || 'مدرس',            description: '',            image: image || '',            codes: [],            semesters: []        };        data.sections[sectionIndex].teachers.push(newTeacher);        saveData();        renderAllData();        updateAllAdminSelects();        addChange();        nameInput.value = '';        if (imageInput) imageInput.value = '';        showToast('success', '✅ تم إضافة المدرس "' + name + '" بنجاح');        renderTeachersListAdmin();    };    window.addSemester = function() {        var sectionSelect = document.getElementById('semesterSection');        var teacherSelect = document.getElementById('semesterTeacher');        var sectionIndex = parseInt(sectionSelect?.value);        var teacherIndex = parseInt(teacherSelect?.value);        var number = parseInt(document.getElementById('semesterNumber').value);        var description = document.getElementById('semesterDesc').value.trim();        if (isNaN(sectionIndex) || sectionIndex < 0 || isNaN(teacherIndex) || teacherIndex < 0 || !number) {            showToast('warning', '⚠️ يرجى اختيار القسم والمدرس وإدخال رقم الفصل');            return;        }        var newSemester = {            number: number,            description: description || 'الفصل ' + number,            lectures: []        };        data.sections[sectionIndex].teachers[teacherIndex].semesters.push(newSemester);        saveData();        renderAllData();        updateAllAdminSelects();        addChange();        document.getElementById('semesterNumber').value = '';        document.getElementById('semesterDesc').value = '';        showToast('success', '✅ تم إضافة الفصل ' + number + ' بنجاح');        renderSemestersListAdmin();    };    window.addLecture = function() {        var sectionSelect = document.getElementById('lectureSection');        var teacherSelect = document.getElementById('lectureTeacher');        var semesterSelect = document.getElementById('lectureSemester');        var sectionIndex = parseInt(sectionSelect?.value);        var teacherIndex = parseInt(teacherSelect?.value);        var semesterIndex = parseInt(semesterSelect?.value);        var numberInput = document.getElementById('lectureNumber');        var titleInput = document.getElementById('lectureTitle');        var urlInput = document.getElementById('lectureUrl');        var freeSelect = document.getElementById('lectureFree');        var number = parseInt(numberInput.value);        var title = titleInput.value.trim();        var youtubeUrl = urlInput.value.trim();        var isFree = freeSelect.value === 'true';        if (isNaN(sectionIndex) || sectionIndex < 0 || isNaN(teacherIndex) || teacherIndex < 0 ||            isNaN(semesterIndex) || semesterIndex < 0 || !number || !title || !youtubeUrl) {            showToast('warning', '⚠️ يرجى ملء جميع الحقول المطلوبة');            return;        }        var isValidUrl = youtubeUrl.includes('mediadelivery') ||            youtubeUrl.includes('youtube') ||            youtubeUrl.includes('youtu.be') ||            youtubeUrl.includes('player.') ||            youtubeUrl.includes('dyntube.com') ||            youtubeUrl.includes('videos.dyntube.com') ||            youtubeUrl.includes('dyntube') ||            youtubeUrl.match(/\.(mp4|webm|ogg|m3u8)(\?.*)?$/i);        if (!isValidUrl) {            showToast('warning', '⚠️ رابط الفيديو غير صحيح. استخدم رابط mediadelivery أو YouTube أو DynTube');            return;        }        var teacher = data.sections[sectionIndex].teachers[teacherIndex];        if (!teacher.semesters) teacher.semesters = [];        if (!teacher.semesters[semesterIndex]) {            teacher.semesters[semesterIndex] = { number: semesterIndex + 1, description: '', lectures: [] };        }        var newLecture = { number: number, title: title, youtubeUrl: youtubeUrl, isFree: isFree };        teacher.semesters[semesterIndex].lectures.push(newLecture);        saveData();        renderAllData();        updateAllAdminSelects();        addChange();        titleInput.value = '';        urlInput.value = '';        numberInput.value = '';        showToast('success', '✅ تم إضافة المحاضرة "' + title + '" بنجاح');        renderLecturesListAdmin();    };    // ============================================================    // تعديل المحاضرة    // ============================================================    window.editLecture = function() {        var sectionSelect = document.getElementById('editLectureSection');        var teacherSelect = document.getElementById('editLectureTeacher');        var semesterSelect = document.getElementById('editLectureSemester');        var lectureSelect = document.getElementById('editLectureSelect');        var titleInput = document.getElementById('editLectureTitle');        var urlInput = document.getElementById('editLectureUrl');        var freeSelect = document.getElementById('editLectureFree');        var messageEl = document.getElementById('editLectureMessage');        var sectionIndex = parseInt(sectionSelect?.value);        var teacherIndex = parseInt(teacherSelect?.value);        var semesterIndex = parseInt(semesterSelect?.value);        var lectureIndex = parseInt(lectureSelect?.value);        if (isNaN(sectionIndex) || sectionIndex < 0) {            messageEl.innerHTML = '⚠️ يرجى اختيار القسم';            messageEl.style.color = '#f59e0b';            return;        }        if (isNaN(teacherIndex) || teacherIndex < 0) {            messageEl.innerHTML = '⚠️ يرجى اختيار المدرس';            messageEl.style.color = '#f59e0b';            return;        }        if (isNaN(semesterIndex) || semesterIndex < 0) {            messageEl.innerHTML = '⚠️ يرجى اختيار الفصل';            messageEl.style.color = '#f59e0b';            return;        }        if (isNaN(lectureIndex) || lectureIndex < 0) {            messageEl.innerHTML = '⚠️ يرجى اختيار المحاضرة';            messageEl.style.color = '#f59e0b';            return;        }        var lecture = data.sections[sectionIndex]?.teachers[teacherIndex]?.semesters[semesterIndex]?.lectures[lectureIndex];        if (!lecture) {            messageEl.innerHTML = '❌ المحاضرة غير موجودة';            messageEl.style.color = '#ef4444';            return;        }        var newTitle = titleInput.value.trim();        var newUrl = urlInput.value.trim();        var newIsFree = freeSelect.value === 'true';        if (!newTitle) {            messageEl.innerHTML = '⚠️ يرجى إدخال العنوان الجديد';            messageEl.style.color = '#f59e0b';            return;        }        if (!newUrl) {            messageEl.innerHTML = '⚠️ يرجى إدخال رابط الفيديو الجديد';            messageEl.style.color = '#f59e0b';            return;        }        var isValidUrl = newUrl.includes('mediadelivery') ||            newUrl.includes('youtube') ||            newUrl.includes('youtu.be') ||            newUrl.includes('player.') ||            newUrl.includes('dyntube.com') ||            newUrl.includes('videos.dyntube.com') ||            newUrl.includes('dyntube') ||            newUrl.match(/\.(mp4|webm|ogg|m3u8)(\?.*)?$/i);        if (!isValidUrl) {            messageEl.innerHTML = '⚠️ رابط الفيديو غير صحيح. استخدم رابط mediadelivery أو YouTube أو DynTube';            messageEl.style.color = '#f59e0b';            return;        }        lecture.title = newTitle;        lecture.youtubeUrl = newUrl;        lecture.isFree = newIsFree;        saveData();        renderAllData();        updateAllAdminSelects();        addChange();        messageEl.innerHTML = '✅ تم تعديل المحاضرة بنجاح!';        messageEl.style.color = '#22c55e';        showToast('success', '✅ تم تعديل المحاضرة "' + newTitle + '" بنجاح');        renderEditLectureList();    };    // ============================================================    // عرض قوائم الإدارة    // ============================================================    function renderSectionsList() {        var container = document.getElementById('sectionsList');        if (!container) return;        if (data.sections.length === 0) {            container.innerHTML = '<p style="color:var(--text-light);text-align:center;padding:0.5rem 0;">لا توجد أقسام</p>';            return;        }        var html = '<div style="margin-top:0.5rem;">';        data.sections.forEach(function(section, index) {            var teacherCount = section.teachers ? section.teachers.length : 0;            html +=                '<div style="display:flex;justify-content:space-between;align-items:center;padding:0.3rem 0.6rem;border-bottom:1px solid var(--border);">' +                '<span><strong>' + section.name + '</strong> (' + teacherCount + ' مدرس)</span>' +                '<button onclick="deleteSection(' + index + ')" class="btn-small btn-danger" style="padding:0.1rem 0.5rem;">🗑️</button>' +                '</div>';        });        html += '</div>';        container.innerHTML = html;    }    window.deleteSection = function(index) {        if (!confirm('⚠️ هل أنت متأكد من حذف القسم "' + data.sections[index].name + '"؟')) return;        data.sections.splice(index, 1);        saveData();        renderAllData();        updateAllAdminSelects();        addChange();        renderSectionsList();        showToast('success', '✅ تم حذف القسم بنجاح');    };    function renderTeachersListAdmin() {        var container = document.getElementById('teachersListAdmin');        if (!container) return;        var html = '';        data.sections.forEach(function(section, si) {            if (section.teachers.length === 0) return;            section.teachers.forEach(function(teacher, ti) {                html +=                    '<div style="display:flex;justify-content:space-between;align-items:center;padding:0.3rem 0.6rem;border-bottom:1px solid var(--border);">' +                    '<span><strong>' + teacher.name + '</strong> - ' + section.name + '</span>' +                    '<button onclick="deleteTeacher(' + si + ', ' + ti + ')" class="btn-small btn-danger" style="padding:0.1rem 0.5rem;">🗑️</button>' +                    '</div>';            });        });        if (!html) {            html = '<p style="color:var(--text-light);text-align:center;padding:0.5rem 0;">لا توجد مدرسين</p>';        }        container.innerHTML = html;    }    window.deleteTeacher = function(sectionIndex, teacherIndex) {        var teacher = data.sections[sectionIndex]?.teachers[teacherIndex];        if (!teacher) return;        if (!confirm('⚠️ هل أنت متأكد من حذف المدرس "' + teacher.name + '"؟')) return;        data.sections[sectionIndex].teachers.splice(teacherIndex, 1);        saveData();        renderAllData();        updateAllAdminSelects();        addChange();        renderTeachersListAdmin();        showToast('success', '✅ تم حذف المدرس بنجاح');    };    function renderSemestersListAdmin() {        var container = document.getElementById('semestersListAdmin');        if (!container) return;        var html = '';        data.sections.forEach(function(section, si) {            if (section.teachers.length === 0) return;            section.teachers.forEach(function(teacher, ti) {                if (!teacher.semesters || teacher.semesters.length === 0) return;                teacher.semesters.forEach(function(semester, smi) {                    var lectureCount = semester.lectures ? semester.lectures.length : 0;                    html +=                        '<div style="display:flex;justify-content:space-between;align-items:center;padding:0.3rem 0.6rem;border-bottom:1px solid var(--border);">' +                        '<span><strong>الفصل ' + semester.number + '</strong> - ' + teacher.name + ' (' + section.name + ') - ' + lectureCount + ' محاضرة</span>' +                        '<button onclick="deleteSemester(' + si + ', ' + ti + ', ' + smi + ')" class="btn-small btn-danger" style="padding:0.1rem 0.5rem;">🗑️</button>' +                        '</div>';                });            });        });        if (!html) {            html = '<p style="color:var(--text-light);text-align:center;padding:0.5rem 0;">لا توجد فصول</p>';        }        container.innerHTML = html;    }    window.deleteSemester = function(sectionIndex, teacherIndex, semesterIndex) {        var semester = data.sections[sectionIndex]?.teachers[teacherIndex]?.semesters[semesterIndex];        if (!semester) return;        if (!confirm('⚠️ هل أنت متأكد من حذف الفصل ' + semester.number + '؟')) return;        data.sections[sectionIndex].teachers[teacherIndex].semesters.splice(semesterIndex, 1);        saveData();        renderAllData();        updateAllAdminSelects();        addChange();        renderSemestersListAdmin();        showToast('success', '✅ تم حذف الفصل بنجاح');    };    function renderLecturesListAdmin() {        var container = document.getElementById('lecturesListAdmin');        if (!container) return;        var html = '';        data.sections.forEach(function(section, si) {            if (section.teachers.length === 0) return;            section.teachers.forEach(function(teacher, ti) {                if (!teacher.semesters || teacher.semesters.length === 0) return;                teacher.semesters.forEach(function(semester, smi) {                    if (!semester.lectures || semester.lectures.length === 0) return;                    semester.lectures.forEach(function(lecture, li) {                        html +=                            '<div style="display:flex;justify-content:space-between;align-items:center;padding:0.3rem 0.6rem;border-bottom:1px solid var(--border);">' +                            '<span><strong>#' + lecture.number + '</strong> ' + lecture.title + ' - ' + teacher.name + ' (' + section.name + ' - الفصل ' + semester.number + ')</span>' +                            '<button onclick="deleteLecture(' + si + ', ' + ti + ', ' + smi + ', ' + li + ')" class="btn-small btn-danger" style="padding:0.1rem 0.5rem;">🗑️</button>' +                            '</div>';                    });                });            });        });        if (!html) {            html = '<p style="color:var(--text-light);text-align:center;padding:0.5rem 0;">لا توجد محاضرات</p>';        }        container.innerHTML = html;    }    window.deleteLecture = function(sectionIndex, teacherIndex, semesterIndex, lectureIndex) {        var lecture = data.sections[sectionIndex]?.teachers[teacherIndex]?.semesters[semesterIndex]?.lectures[lectureIndex];        if (!lecture) return;        if (!confirm('⚠️ هل أنت متأكد من حذف المحاضرة "' + lecture.title + '"؟')) return;        data.sections[sectionIndex].teachers[teacherIndex].semesters[semesterIndex].lectures.splice(lectureIndex, 1);        saveData();        renderAllData();        updateAllAdminSelects();        addChange();        renderLecturesListAdmin();        showToast('success', '✅ تم حذف المحاضرة بنجاح');    };    function renderEditLectureList() {        var container = document.getElementById('editLectureListAdmin');        if (!container) return;        var html = '';        data.sections.forEach(function(section, si) {            if (section.teachers.length === 0) return;            section.teachers.forEach(function(teacher, ti) {                if (!teacher.semesters || teacher.semesters.length === 0) return;                teacher.semesters.forEach(function(semester, smi) {                    if (!semester.lectures || semester.lectures.length === 0) return;                    semester.lectures.forEach(function(lecture, li) {                        html +=                            '<div style="display:flex;justify-content:space-between;align-items:center;padding:0.3rem 0.6rem;border-bottom:1px solid var(--border);">' +                            '<span><strong>#' + lecture.number + '</strong> ' + lecture.title + ' - ' + teacher.name + ' (' + section.name + ' - الفصل ' + semester.number + ')</span>' +                            '<button onclick="loadLectureForEdit(' + si + ', ' + ti + ', ' + smi + ', ' + li + ')" class="btn-small btn-primary" style="padding:0.1rem 0.5rem;">✏️ تعديل</button>' +                            '<button onclick="deleteLecture(' + si + ', ' + ti + ', ' + smi + ', ' + li + ')" class="btn-small btn-danger" style="padding:0.1rem 0.5rem;">🗑️</button>' +                            '</div>';                    });                });            });        });        if (!html) {            html = '<p style="color:var(--text-light);text-align:center;padding:0.5rem 0;">لا توجد محاضرات</p>';        }        container.innerHTML = html;    }    window.loadLectureForEdit = function(sectionIndex, teacherIndex, semesterIndex, lectureIndex) {        var lecture = data.sections[sectionIndex]?.teachers[teacherIndex]?.semesters[semesterIndex]?.lectures[lectureIndex];        if (!lecture) return;        document.getElementById('editLectureSection').value = sectionIndex;        document.getElementById('editLectureTeacher').value = teacherIndex;        document.getElementById('editLectureSemester').value = semesterIndex;        document.getElementById('editLectureSelect').value = lectureIndex;        document.getElementById('editLectureTitle').value = lecture.title || '';        document.getElementById('editLectureUrl').value = lecture.youtubeUrl || '';        document.getElementById('editLectureFree').value = lecture.isFree ? 'true' : 'false';        var msg = document.getElementById('editLectureMessage');        if (msg) { msg.innerHTML = '✅ تم تحميل المحاضرة للتعديل';            msg.style.color = '#22c55e'; }        showToast('info', '📝 تم تحميل المحاضرة للتعديل');    };    // ============================================================    // إدارة الأكواد    // ============================================================    window.addManualCode = function() {        var sectionSelect = document.getElementById('codeSection');        var teacherSelect = document.getElementById('codeTeacherSelect');        var codeInput = document.getElementById('manualCodeInput');        var codeMessage = document.getElementById('manualCodeMessage');        var sectionIndex = parseInt(sectionSelect?.value);        var teacherIndex = parseInt(teacherSelect?.value);        var code = codeInput?.value.trim().toUpperCase();        if (isNaN(sectionIndex) || sectionIndex < 0) {            codeMessage.innerHTML = '⚠️ يرجى اختيار القسم أولاً';            codeMessage.style.color = '#f59e0b';            return;        }        if (isNaN(teacherIndex) || teacherIndex < 0) {            codeMessage.innerHTML = '⚠️ يرجى اختيار المدرس أولاً';            codeMessage.style.color = '#f59e0b';            return;        }        if (!code) {            codeMessage.innerHTML = '⚠️ يرجى إدخال الكود';            codeMessage.style.color = '#f59e0b';            return;        }        if (code.length < 4) {            codeMessage.innerHTML = '⚠️ الكود قصير جداً';            codeMessage.style.color = '#f59e0b';            return;        }        var teacher = data.sections[sectionIndex].teachers[teacherIndex];        if (!teacher) {            codeMessage.innerHTML = '❌ المدرس غير موجود';            codeMessage.style.color = '#ef4444';            return;        }        if (!teacher.codes) teacher.codes = [];        var exists = teacher.codes.some(function(c) { return c.code === code; });        if (exists) {            codeMessage.innerHTML = '⚠️ هذا الكود موجود بالفعل';            codeMessage.style.color = '#f59e0b';            return;        }        teacher.codes.push({            code: code,            used: false,            locked: false,            deviceId: null,            userId: null,            userEmail: null,            usedAt: null        });        saveData();        addChange();        updateCodesManagement();        if (codeInput) codeInput.value = '';        codeMessage.innerHTML = '✅ تم إضافة الكود: ' + code;        codeMessage.style.color = '#22c55e';        showToast('success', '✅ تم إضافة الكود: ' + code);        updateAllAdminSelects();    };    window.generateCodes = function(count) {        count = count || 5;        var sectionSelect = document.getElementById('codeSection');        var teacherSelect = document.getElementById('codeTeacherSelect');        var sectionIndex = parseInt(sectionSelect?.value);        var teacherIndex = parseInt(teacherSelect?.value);        if (isNaN(sectionIndex) || sectionIndex < 0) {            showToast('warning', '⚠️ يرجى اختيار القسم أولاً');            return;        }        if (isNaN(teacherIndex) || teacherIndex < 0) {            showToast('warning', '⚠️ يرجى اختيار المدرس أولاً');            return;        }        var teacher = data.sections[sectionIndex].teachers[teacherIndex];        if (!teacher) { showToast('error', '❌ المدرس غير موجود'); return; }        if (!teacher.codes) teacher.codes = [];        var newCodes = [];        for (var i = 0; i < count; i++) {            var prefix = teacher.name.substring(0, 3).toUpperCase().replace(/[^A-Z]/g, 'X');            var chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';            var random = '';            for (var j = 0; j < 8; j++) {                random += chars.charAt(Math.floor(Math.random() * chars.length));            }            var newCode = prefix + '-' + random;            teacher.codes.push({                code: newCode,                used: false,                locked: false,                deviceId: null,                userId: null,                userEmail: null,                usedAt: null            });            newCodes.push(newCode);        }        saveData();        addChange();        updateCodesManagement();        showToast('success', '✅ تم إنشاء ' + newCodes.length + ' أكواد جديدة');        updateAllAdminSelects();    };    function updateCodesManagement() {        var sectionSelect = document.getElementById('codeSection');        var teacherSelect = document.getElementById('codeTeacherSelect');        var container = document.getElementById('codesListContainer');        var sectionIndex = parseInt(sectionSelect?.value);        var teacherIndex = parseInt(teacherSelect?.value);        if (isNaN(sectionIndex) || sectionIndex < 0) {            container.innerHTML = '<p style="color:var(--text-light);text-align:center;padding:1rem 0;">اختر القسم أولاً</p>';            return;        }        if (isNaN(teacherIndex) || teacherIndex < 0) {            container.innerHTML = '<p style="color:var(--text-light);text-align:center;padding:1rem 0;">اختر المدرس أولاً</p>';            return;        }        var teacher = data.sections[sectionIndex]?.teachers[teacherIndex];        if (!teacher) {            container.innerHTML = '<p style="color:var(--text-light);text-align:center;padding:1rem 0;">المدرس غير موجود</p>';            return;        }        var status = getCodesStatus(teacher);        var html =            '<div class="codes-stats">' +            '<span>📊 المجموع: ' + status.total + '</span>' +            '<span>✅ المستخدمة: ' + status.used + '</span>' +            '<span>🟢 المتاحة: ' + status.available + '</span>' +            '<span>🔒 المقفلة: ' + status.locked + '</span>' +            '</div>' +            '<div class="codes-table-wrapper">' +            '<table class="codes-table">' +            '<thead><tr><th>#</th><th>الكود</th><th>الحالة</th><th>تاريخ الاستخدام</th><th>الإجراءات</th></tr></thead>' +            '<tbody>';        if (teacher.codes && teacher.codes.length > 0) {            teacher.codes.forEach(function(c, index) {                var isUsed = c.used;                var isLocked = c.locked || false;                var isMyCode = c.userEmail === currentUser?.email;                var statusText = '',                    statusColor = '#22c55e',                    usedAtDisplay = '—';                if (isLocked) { statusText = '🔒 مقفل';                    statusColor = '#f59e0b'; } else if (isUsed) {                    statusText = isMyCode ? '✅ حسابك' : '❌ مستخدم';                    statusColor = isMyCode ? '#22c55e' : '#ef4444';                    usedAtDisplay = c.usedAt ? new Date(c.usedAt).toLocaleString('ar') : 'غير معروف';                } else { statusText = '🟢 متاح';                    statusColor = '#22c55e'; }                html +=                    '<tr>' +                    '<td>' + (index + 1) + '</td>' +                    '<td><code style="font-weight:700;color:' + statusColor + ';">' + c.code + '</code></td>' +                    '<td><span style="color:' + statusColor + ';">' + statusText + '</span></td>' +                    '<td style="font-size:0.7rem;color:var(--text-light);">' + usedAtDisplay + '</td>' +                    '<td>' +                    '<button onclick="toggleCodeLock(\'' + sectionIndex + '\', \'' + teacherIndex + '\', \'' + c.code + '\')" style="background:' + (isLocked ? '#22c55e' : '#f59e0b') + ';color:white;border:none;border-radius:4px;padding:0.15rem 0.5rem;cursor:pointer;font-size:0.7rem;">' +                    (isLocked ? '🔓 فتح' : '🔒 قفل') +                    '</button>' +                    (!isUsed && !isLocked ? '<button onclick="deleteCodeAction(\'' + sectionIndex + '\', \'' + teacherIndex + '\', \'' + c.code + '\')" style="background:#ef4444;color:white;border:none;border-radius:4px;padding:0.15rem 0.5rem;cursor:pointer;font-size:0.7rem;">🗑️</button>' : '') +                    '</td>' +                    '</tr>';            });        } else {            html +=                '<tr><td colspan="5" style="text-align:center;color:var(--text-light);padding:1rem 0;">لا توجد أكواد</td></tr>';        }        html += '</tbody></table></div>';        container.innerHTML = html;    }    window.toggleCodeLock = function(sectionIndex, teacherIndex, code) {        var teacher = data.sections[sectionIndex]?.teachers[teacherIndex];        if (!teacher) { showToast('error', '❌ المدرس غير موجود'); return; }        var codeData = teacher.codes.find(function(c) { return c.code === code; });        if (!codeData) { showToast('error', '❌ الكود غير موجود'); return; }        codeData.locked = !codeData.locked;        saveData();        addChange();        updateCodesManagement();        showToast('success', '✅ تم ' + (codeData.locked ? 'قفل' : 'فتح') + ' الكود ' + code);    };    window.deleteCodeAction = function(sectionIndex, teacherIndex, code) {        if (!confirm('⚠️ هل أنت متأكد من حذف الكود: ' + code + '؟')) return;        var teacher = data.sections[sectionIndex]?.teachers[teacherIndex];        if (!teacher) { showToast('error', '❌ المدرس غير موجود'); return; }        var index = teacher.codes.findIndex(function(c) { return c.code === code; });        if (index === -1) { showToast('error', '❌ الكود غير موجود'); return; }        if (teacher.codes[index].used) {            showToast('warning', '⚠️ لا يمكن حذف كود مستخدم');            return;        }        teacher.codes.splice(index, 1);        saveData();        addChange();        updateCodesManagement();        showToast('success', '✅ تم حذف الكود: ' + code);    };    // ============================================================    // تعديل المدرس    // ============================================================    var editTeacherSection = document.getElementById('editTeacherSection');    var editTeacherSelect = document.getElementById('editTeacherSelect');    if (editTeacherSection) {        editTeacherSection.addEventListener('change', function() {            updateAllAdminSelects();        });    }    if (editTeacherSelect) {        editTeacherSelect.addEventListener('change', function() {            updateEditTeacherData();        });    }    var editTeacherForm = document.getElementById('editTeacherForm');    if (editTeacherForm) {        editTeacherForm.addEventListener('submit', function(e) {            e.preventDefault();            var sectionSelect = document.getElementById('editTeacherSection');            var teacherSelect = document.getElementById('editTeacherSelect');            var messageEl = document.getElementById('editTeacherMessage');            var sectionIndex = parseInt(sectionSelect?.value);            var teacherIndex = parseInt(teacherSelect?.value);            if (isNaN(sectionIndex) || sectionIndex < 0) {                messageEl.innerHTML = '⚠️ يرجى اختيار القسم';                messageEl.style.color = '#f59e0b';                return;            }            if (isNaN(teacherIndex) || teacherIndex < 0) {                messageEl.innerHTML = '⚠️ يرجى اختيار المدرس';                messageEl.style.color = '#f59e0b';                return;            }            var teacher = data.sections[sectionIndex].teachers[teacherIndex];            if (!teacher) {                messageEl.innerHTML = '❌ المدرس غير موجود';                messageEl.style.color = '#ef4444';                return;            }            var newName = document.getElementById('editTeacherName').value.trim();            var newSubject = document.getElementById('editTeacherSubject').value.trim();            var newDesc = document.getElementById('editTeacherDesc').value.trim();            var newImage = document.getElementById('editTeacherImage').value.trim();            if (!newName) {                messageEl.innerHTML = '⚠️ يرجى إدخال اسم المدرس';                messageEl.style.color = '#f59e0b';                return;            }            teacher.name = newName;            teacher.subject = newSubject || 'مدرس';            teacher.description = newDesc || '';            teacher.image = newImage || '';            saveData();            renderAllData();            updateAllAdminSelects();            addChange();            messageEl.innerHTML = '✅ تم تعديل بيانات المدرس "' + newName + '" بنجاح!';            messageEl.style.color = '#22c55e';            showToast('success', '✅ تم تعديل بيانات المدرس "' + newName + '"');            renderTeachersListAdmin();        });    }    // ============================================================    // إدارة المشرفين    // ============================================================    window.addNewAdmin = async function() {        var emailInput = document.getElementById('adminEmailInput');        var messageEl = document.getElementById('addAdminMessage');        var email = emailInput.value.trim();        if (!email) {            messageEl.innerHTML = '⚠️ يرجى إدخال البريد الإلكتروني';            messageEl.style.color = '#f59e0b';            return;        }        if (!email.includes('@') || !email.includes('.')) {            messageEl.innerHTML = '⚠️ البريد الإلكتروني غير صحيح';            messageEl.style.color = '#f59e0b';            return;        }        if (!supabaseClient) {            messageEl.innerHTML = '❌ Supabase غير متاح';            messageEl.style.color = '#ef4444';            return;        }        try {            var userResult = await supabaseClient                .from('users')                .select('id, email')                .eq('email', email)                .maybeSingle();            if (!userResult.data) {                messageEl.innerHTML =                    '⚠️ المستخدم <strong>' + email + '</strong> غير موجود.';                messageEl.style.color = '#f59e0b';                return;            }            var adminCheck = await supabaseClient                .from('admins')                .select('email')                .eq('email', email)                .maybeSingle();            if (adminCheck.data) {                messageEl.innerHTML = '⚠️ هذا المستخدم مشرف بالفعل';                messageEl.style.color = '#f59e0b';                return;            }            var insertResult = await supabaseClient                .from('admins')                .insert({ uid: userResult.data.id, email: email, role: 'admin' });            if (insertResult.error) {                messageEl.innerHTML = '❌ فشل إضافة المشرف: ' + insertResult.error.message;                messageEl.style.color = '#ef4444';                return;            }            messageEl.innerHTML = '✅ تم إضافة المشرف: ' + email + ' بنجاح!';            messageEl.style.color = '#22c55e';            emailInput.value = '';            showToast('success', '✅ تم إضافة المشرف: ' + email);            loadAdminsList();        } catch (error) {            messageEl.innerHTML = '❌ حدث خطأ: ' + error.message;            messageEl.style.color = '#ef4444';            console.error('Error adding admin:', error);        }    };    async function loadAdminsList() {        var container = document.getElementById('adminsListContainer');        if (!container) return;        if (!supabaseClient) {            container.innerHTML = '<p style="color:var(--text-light);text-align:center;">⚠️ Supabase غير متاح</p>';            return;        }        try {            var result = await supabaseClient                .from('admins')                .select('email, uid, created_at')                .order('created_at', { ascending: true });            if (result.error) {                container.innerHTML = '<p style="color:var(--text-light);text-align:center;">❌ فشل تحميل المشرفين</p>';                return;            }            var admins = result.data;            if (!admins || admins.length === 0) {                container.innerHTML = '<p style="color:var(--text-light);text-align:center;">لا يوجد مشرفين حتى الآن</p>';                return;            }            var html =                '<div style="overflow-x:auto;">' +                '<table class="admins-table">' +                '<thead><tr><th>#</th><th>البريد الإلكتروني</th><th>تاريخ الإضافة</th><th>إجراء</th></tr></thead>' +                '<tbody>';            admins.forEach(function(admin, index) {                var isCurrentUser = admin.email === currentUser?.email;                var createdAt = admin.created_at ? new Date(admin.created_at).toLocaleDateString('ar') : 'غير معروف';                html +=                    '<tr>' +                    '<td>' + (index + 1) + '</td>' +                    '<td>' + admin.email + (isCurrentUser ? ' 👑 (أنت)' : '') + '</td>' +                    '<td style="color:var(--text-light);font-size:0.7rem;">' + createdAt + '</td>' +                    '<td>' +                    (!isCurrentUser ? '<button onclick="deleteAdmin(\'' + admin.email + '\')" class="btn-delete-admin">🗑️ حذف</button>' : '<span style="color:var(--text-light);font-size:0.7rem;">لا يمكن حذف نفسك</span>') +                    '</td>' +                    '</tr>';            });            html += '</tbody></table></div>';            container.innerHTML = html;        } catch (error) {            container.innerHTML = '<p style="color:var(--text-light);text-align:center;">❌ فشل تحميل المشرفين</p>';            console.error('Error loading admins:', error);        }    }    window.deleteAdmin = async function(email) {        if (!confirm('⚠️ هل أنت متأكد من حذف المشرف: ' + email + '؟')) return;        if (!supabaseClient) {            showToast('error', '❌ Supabase غير متاح');            return;        }        try {            var result = await supabaseClient                .from('admins')                .delete()                .eq('email', email);            if (result.error) {                showToast('error', '❌ فشل حذف المشرف: ' + result.error.message);                return;            }            showToast('success', '✅ تم حذف المشرف: ' + email);            loadAdminsList();        } catch (error) {            showToast('error', '❌ حدث خطأ: ' + error.message);            console.error('Error deleting admin:', error);        }    };    // ============================================================    // عرض جدول المستخدمين    // ============================================================    function renderUsersTable() {        var tbody = document.getElementById('usersTableBody');        if (!tbody) return;        var usersMap = new Map();        data.sections.forEach(function(section) {            section.teachers.forEach(function(teacher) {                if (teacher.codes) {                    teacher.codes.forEach(function(c) {                        if (c.used && c.userEmail) {                            if (!usersMap.has(c.userEmail)) {                                usersMap.set(c.userEmail, {                                    email: c.userEmail,                                    userId: c.userId || 'غير معروف',                                    courses: [],                                    registeredAt: c.usedAt || new Date().toISOString(),                                    progress: 0                                });                            }                            if (!usersMap.get(c.userEmail).courses.includes(teacher.name)) {                                usersMap.get(c.userEmail).courses.push(teacher.name);                            }                        }                    });                }            });        });        if (usersMap.size === 0) {            tbody.innerHTML =                '<tr><td colspan="7" style="text-align:center;color:var(--text-light);padding:1rem 0;">لا يوجد مستخدمين مسجلين</td></tr>';            return;        }        var html = '';        var index = 1;        usersMap.forEach(function(user) {            var isAdmin = user.email === currentUser?.email && isAdminLoggedIn;            var courseCount = user.courses.length;            var progress = user.progress || 0;            html +=                '<tr>' +                '<td>' + (index++) + '</td>' +                '<td>' + user.email + '</td>' +                '<td>' + user.courses.join('، ') + '</td>' +                '<td>' + courseCount + '</td>' +                '<td>' + progress + '%</td>' +                '<td>' + new Date(user.registeredAt).toLocaleDateString('ar') + '</td>' +                '<td><span class="badge ' + (isAdmin ? 'admin' : 'user') + '">' + (isAdmin ? 'مدير' : 'مستخدم') + '</span></td>' +                '</tr>';        });        tbody.innerHTML = html;    }    // ============================================================    // فلتر الطلاب    // ============================================================    window.filterStudents = function() {        var sectionFilter = document.getElementById('studentSectionFilter');        var teacherFilter = document.getElementById('studentTeacherFilter');        var tbody = document.getElementById('studentsTableBody');        var sectionIndex = parseInt(sectionFilter?.value);        var teacherIndex = parseInt(teacherFilter?.value);        var usersMap = new Map();        data.sections.forEach(function(section, si) {            if (!isNaN(sectionIndex) && sectionIndex >= 0 && si !== sectionIndex) return;            section.teachers.forEach(function(teacher, ti) {                if (!isNaN(teacherIndex) && teacherIndex >= 0 && ti !== teacherIndex) return;                if (teacher.codes) {                    teacher.codes.forEach(function(c) {                        if (c.used && c.userEmail) {                            if (!usersMap.has(c.userEmail)) {                                var totalLectures = 0;                                var completedLectures = 0;                                if (teacher.semesters) {                                    if (!teacher.id) {                                        teacher.id = 'teacher_' + Date.now() + '_' + Math.random().toString(36).substr(2,                                        6);                                    }                                    teacher.semesters.forEach(function(semester, smi) {                                        if (semester.lectures) {                                            semester.lectures.forEach(function(lecture, li) {                                                totalLectures++;                                                if (isLectureWatched(teacher.id, smi, li)) {                                                    completedLectures++;                                                }                                            });                                        }                                    });                                }                                var progress = totalLectures > 0 ? Math.round((completedLectures /                                    totalLectures) * 100) : 0;                                usersMap.set(c.userEmail, {                                    email: c.userEmail,                                    sectionName: section.name,                                    teacherName: teacher.name,                                    teacherId: teacher.id,                                    totalLectures: totalLectures,                                    completedLectures: completedLectures,                                    progress: progress,                                    registeredAt: c.usedAt || new Date().toISOString()                                });                            }                        }                    });                }            });        });        if (usersMap.size === 0) {            tbody.innerHTML =                '<tr><td colspan="8" style="text-align:center;color:var(--text-light);padding:0.8rem 0;font-size:0.65rem;"><i class="fas fa-users" style="font-size:1.2rem;display:block;margin-bottom:0.2rem;"></i>لا يوجد طلاب مسجلين</td></tr>';            return;        }        var html = '';        var index = 1;        usersMap.forEach(function(user) {            html +=                '<tr>' +                '<td>' + (index++) + '</td>' +                '<td>' + user.email + '</td>' +                '<td>' + user.sectionName + '</td>' +                '<td>' + user.teacherName + '</td>' +                '<td>' + user.totalLectures + '</td>' +                '<td>' + user.completedLectures + '</td>' +                '<td class="progress-cell">' +                '<div class="mini-bar">' +                '<div class="mini-fill" style="width:' + user.progress + '%;"></div>' +                '</div>' +                '<span class="mini-label">' + user.progress + '%</span>' +                '</td>' +                '<td><button onclick="showStudentProgress(\'' + user.email + '\', \'' + user.teacherName + '\')" class="btn-small btn-primary" style="padding:0.1rem 0.4rem;font-size:0.5rem;">📊 عرض التقدم</button></td>' +                '</tr>';        });        tbody.innerHTML = html;    };    // ============================================================    // الإعدادات - صورة الإعلان    // ============================================================    window.updateBanner = function() {        var urlInput = document.getElementById('bannerUrlInput');        var message = document.getElementById('bannerMessage');        var url = urlInput.value.trim();        if (!url) {            message.innerHTML = '⚠️ يرجى إدخال رابط الصورة';            message.style.color = '#f59e0b';            return;        }        try {            new URL(url);        } catch (e) {            message.innerHTML = '⚠️ الرابط غير صحيح';            message.style.color = '#f59e0b';            return;        }        localStorage.setItem('bannerImage', url);        var img = document.getElementById('bannerImage');        var placeholder = document.getElementById('bannerPlaceholder');        if (img) { img.src = url;            img.style.display = 'block'; }        if (placeholder) placeholder.style.display = 'none';        var mainBanner = document.getElementById('mainBannerImage');        var mainPlaceholder = document.getElementById('mainBannerPlaceholder');        if (mainBanner) { mainBanner.src = url;            mainBanner.style.display = 'block'; }        if (mainPlaceholder) mainPlaceholder.style.display = 'none';        message.innerHTML = '✅ تم تحديث صورة الإعلان بنجاح';        message.style.color = '#22c55e';        showToast('success', '✅ تم تحديث صورة الإعلان');    };    // ============================================================    // الإعدادات - مسح الكاش    // ============================================================    window.clearCache = function() {        if (!confirm('⚠️ هل أنت متأكد من مسح الكاش؟')) return;        try {            localStorage.removeItem('academyData');            localStorage.removeItem('devAcademicUser');            localStorage.removeItem('devAcademicTheme');            localStorage.removeItem('bannerImage');            localStorage.removeItem('studentProgress_' + (currentUser ? currentUser.id : 'guest'));            document.cookie.split(';').forEach(function(c) {                document.cookie = c.replace(/^ +/, '').replace(/=.*/, '=;expires=' + new Date().toUTCString() +                    ';path=/');            });            showToast('success', '✅ تم مسح الكاش بنجاح');            setTimeout(function() { window.location.reload(); }, 800);        } catch (error) {            showToast('error', '❌ فشل مسح الكاش');        }    };    // ============================================================    // الإعدادات - تصدير البيانات    // ============================================================    window.exportData = function() {        try {            var dataStr = JSON.stringify(data, null, 2);            var blob = new Blob([dataStr], { type: 'application/json' });            var url = URL.createObjectURL(blob);            var a = document.createElement('a');            a.href = url;            a.download = 'dev_academy_data_' + new Date().toISOString().slice(0, 10) + '.json';            a.click();            URL.revokeObjectURL(url);            showToast('success', '✅ تم تصدير البيانات بنجاح');        } catch (error) {            showToast('error', '❌ فشل تصدير البيانات');        }    };    // ============================================================    // الإعدادات - حذف جميع البيانات    // ============================================================    window.deleteAllData = function() {        if (!confirm('⚠️ تحذير! هذا الإجراء سيحذف جميع البيانات بشكل نهائي. هل أنت متأكد؟')) return;        if (!confirm('⚠️ تأكيد نهائي: هل أنت متأكد من حذف جميع البيانات؟')) return;        try {            localStorage.removeItem('academyData');            localStorage.removeItem('devAcademicUser');            localStorage.removeItem('devAcademicTheme');            localStorage.removeItem('bannerImage');            localStorage.removeItem('deviceId');            localStorage.removeItem('studentProgress_' + (currentUser ? currentUser.id : 'guest'));            data = { sections: JSON.parse(JSON.stringify(defaultSections)) };            normalizeDataStructure(data);            saveData();            renderAllData();            updateAllAdminSelects();            showToast('success', '✅ تم حذف جميع البيانات');            setTimeout(function() { window.location.reload(); }, 800);        } catch (error) {            showToast('error', '❌ فشل حذف البيانات');        }    };    // ============================================================    // النشر    // ============================================================    if (publishBtn) {        publishBtn.addEventListener('click', async function() {            if (pendingChanges === 0) {                showToast('info', '📌 لا توجد تغييرات لنشرها');                return;            }            if (!supabaseClient) {                showToast('error', '❌ Supabase غير متاح');                return;            }            var isAdmin = await checkIsAdmin(currentUser?.email);            if (!isAdmin) {                showToast('error', '❌ يجب تسجيل الدخول كمشرف');                return;            }            var result = await saveSupabaseAcademyData();            if (!result.success) {                showToast('error', '❌ فشل النشر: ' + (result.error?.message || 'خطأ غير معروف'));                return;            }            pendingChanges = 0;            updatePendingChanges();            showToast('success', '✅ تم نشر التغييرات بنجاح');            var msg = document.getElementById('publishMessage');            if (msg) { msg.textContent = '✅ تم نشر التغييرات بنجاح';                msg.style.color = '#22c55e'; }            setTimeout(function() { if (msg) msg.textContent = ''; }, 5000);        });    }    // ============================================================    // التهيئة    // ============================================================    var savedTheme = localStorage.getItem('devAcademicTheme');    if (savedTheme === 'dark') {        isDarkMode = true;        document.body.classList.add('dark-mode');        themeToggle.innerHTML = '<i class="fas fa-sun"></i>';    }    var savedBanner = localStorage.getItem('bannerImage');    if (savedBanner) {        var img = document.getElementById('bannerImage');        var placeholder = document.getElementById('bannerPlaceholder');        if (img) { img.src = savedBanner;            img.style.display = 'block'; }        if (placeholder) placeholder.style.display = 'none';        var urlInput = document.getElementById('bannerUrlInput');        if (urlInput) urlInput.value = savedBanner;        var mainBanner = document.getElementById('mainBannerImage');        var mainPlaceholder = document.getElementById('mainBannerPlaceholder');        if (mainBanner) { mainBanner.src = savedBanner;            mainBanner.style.display = 'block'; }        if (mainPlaceholder) mainPlaceholder.style.display = 'none';    }    async function init() {        if (supabaseClient) {            try {                var sessionResult = await supabaseClient.auth.getSession();                var session = sessionResult.data.session;                if (session?.user) {                    currentUser = session.user;                    localStorage.setItem('devAcademicUser', JSON.stringify({                        email: currentUser.email,                        name: currentUser.user_metadata?.full_name || ''                    }));                    loadStudentProgress();                    updateUI();                    await loadUserCodesFromSupabase();                    renderAllData();                    renderMyCourses();                    renderAccount();                    updateBadge();                    loadingScreen.classList.add('hidden');                    app.style.display = 'block';                    navbar.style.display = 'flex';                    bottomNav.style.display = 'flex';                    navigateTo('home');                    showToast('success', '✅ مرحباً بعودتك');                    console.log('👤 المستخدم:', currentUser.email);                } else {                    window.location.href = 'index.html';                }            } catch (error) {                console.warn('Session check error:', error);                window.location.href = 'index.html';            }        } else {            window.location.href = 'index.html';        }        if (supabaseClient && currentUser) {            try {                var channel = supabaseClient                    .channel('public:academy_data')                    .on('postgres_changes', {                        event: 'UPDATE',                        schema: 'public',                        table: 'academy_data',                        filter: 'id=eq.main'                    }, function(payload) {                        if (!payload?.new?.content) return;                        try {                            var remoteData = payload.new.content;                            if (JSON.stringify(remoteData) !== JSON.stringify(data)) {                                data = remoteData;                                normalizeDataStructure(data);                                saveData();                                renderAllData();                                renderMyCourses();                                renderAccount();                                updateBadge();                                showToast('info', '🔄 تم تحديث البيانات تلقائياً');                            }                        } catch (err) { console.warn('Realtime parse error:', err); }                    })                    .subscribe();                console.log('✅ مشترك في تحديثات Supabase');            } catch (error) {                console.warn('Supabase realtime subscription failed:', error);            }        }        renderUsersTable();        updateAllAdminSelects();        loadAdminsList();        renderSectionsList();        renderTeachersListAdmin();        renderSemestersListAdmin();        renderLecturesListAdmin();        renderEditLectureList();        filterStudents();        console.log('📚 ديف أكاديمي - النظام جاهز مع الأقسام والفلتر');        console.log('🔒 جميع الميزات محمية وآمنة');        console.log('🎥 دعم منصة mediadelivery و YouTube و DynTube للتشغيل');        console.log('👑 قسم إدارة المشرفين مفعل مع دالة RPC');    }    loadData().then(init).catch(function(error) {        console.error('Initialization failed:', error);        window.location.href = 'index.html';    });})();